const CACHE_NAME = 'tüka-v1';
const urlsToCache = [
  '/',
  '/index.html',
  '/manifest.json',
  '/images/logo.webp'
];

// Install event - cache resources
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then((cache) => {
        console.log('Opened cache');
        return cache.addAll(urlsToCache);
      })
  );
});

// Fetch event - serve from cache when offline
self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request)
      .then((response) => {
        // Return cached version or fetch from network
        return response || fetch(event.request);
      })
  );
});

// Activate event - clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            console.log('Deleting old cache:', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
});

// Push notification handling
self.addEventListener('push', (event) => {
  const options = {
    body: event.data ? event.data.text() : 'Neue Nachricht verfügbar',
    icon: '/images/logo.webp',
    badge: '/images/logo.webp',
    vibrate: [100, 50, 100],
    data: {
      dateOfArrival: Date.now(),
      primaryKey: 1
    },
    actions: [
      {
        action: 'explore',
        title: 'Öffnen',
        icon: '/images/logo.webp'
      },
      {
        action: 'close',
        title: 'Schließen',
        icon: '/images/logo.webp'
      }
    ]
  };

  event.waitUntil(
    self.registration.showNotification('tüka', options)
  );
});

// Notification click handling
self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  if (event.action === 'explore') {
    event.waitUntil(
      clients.openWindow('/')
    );
  }
});

const express = require('express');
const path = require('path');
const app = express();
const PORT = 5173;

// Statische Dateien aus public und src ausliefern
app.use('/images', express.static(path.join(__dirname, 'public/images')));
app.use('/src', express.static(path.join(__dirname, 'src')));
app.use('/@vite', express.static(path.join(__dirname, 'node_modules/vite/dist/client')));

// Für alle anderen Routen index.html ausliefern (SPA-Fallback)
app.get('*', (req, res) => {
  res.sendFile(path.join(__dirname, 'index.html'));
});

app.listen(PORT, '0.0.0.0', () => {
  console.log(`Simple server running on http://localhost:${PORT}/`);
  console.log('Serving index.html for all routes');
});

