const AdCard: React.FC<AdCardProps> = ({ id, title, price, location, images, category, status, views, created_at, attributes, seller, vehicleDetails }) => {
  const { user } = useUser();
  const { isFavorite: isFavoriteGlobal, addFavorite, removeFavorite } = useFavorites();
  const navigate = useNavigate();
  const [anchorEl, setAnchorEl] = React.useState<null | HTMLElement>(null);
  const [isLoading, setIsLoading] = React.useState(false);
  const [currentImageIndex, setCurrentImageIndex] = React.useState(0);
  const [isHovering, setIsHovering] = React.useState(false);
  const [adminEditOpen, setAdminEditOpen] = React.useState(false);
  const hoverIntervalRef = React.useRef<number | null>(null);
  const isMobile = useMediaQuery('(max-width:600px)');
  const open = Boolean(anchorEl);

  // Verwende den globalen Favoriten-Status
  const favoriteState = isFavoriteGlobal(id);

  const handleMenuOpen = (event: React.MouseEvent<HTMLElement>) => {
    event.stopPropagation();
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => setAnchorEl(null);

  const handleCardClick = () => {
    navigate(`/listing/${id}`);
  };

  const handleFavoriteToggle = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (!user) {
      return;
    }

    setIsLoading(true);
    try {
      if (favoriteState) {
        await removeFavorite(id);
      } else {
        await addFavorite(id);
      }
    } catch (error: unknown) {
      // Fehler beim Umschalten der Favoriten
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = (e: React.MouseEvent) => {
    e.stopPropagation();
    const url = `${window.location.origin}/listing/${id}`;
    if (navigator.share) {
      navigator.share({
        title: title,
        text: `${title} - ${formatPrice(price)}`,
        url: url
      });
    } else {
      navigator.clipboard.writeText(url);
    }
    handleMenuClose();
  };

  const handleReport = (e: React.MouseEvent) => {
    e.stopPropagation();
    handleMenuClose();
  };

  // Bild-Array verarbeiten
  let imgs: string[] = [];
  try {
    if (images) {
      console.log(`AdCard ${id}: Raw images data:`, images);
      if (typeof images === 'string') {
        try {
          imgs = JSON.parse(images);
          console.log(`AdCard ${id}: Parsed JSON images:`, imgs);
        } catch {
          imgs = [images];
          console.log(`AdCard ${id}: Single image string:`, imgs);
        }
      } else if (Array.isArray(images)) {
        imgs = images;
        console.log(`AdCard ${id}: Array images:`, imgs);
      }
    }
  } catch (error) {
    console.warn('Fehler beim Parsen der Bilder:', error);
    imgs = [];
  }

  if (!imgs || imgs.length === 0) {
    console.log(`AdCard ${id}: No images found, using placeholder`);
    imgs = ['/images/noimage.jpeg'];
  }

  const displayImages = imgs.length === 1 ? [imgs[0], imgs[0]] : imgs;
  const currentImage = displayImages[currentImageIndex] || displayImages[0];

  console.log(`AdCard ${id}: Current image:`, currentImage);

  // Verwende die zentrale getImageUrl Funktion
  const imageUrl = getImageUrlFromUtils(currentImage);
  console.log(`AdCard ${id}: Final imageUrl:`, imageUrl);

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('de-DE', {
      style: 'currency',
      currency: 'EUR',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(price);
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffTime = Math.abs(now.getTime() - date.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays === 1) return 'Heute';
    if (diffDays === 2) return 'Gestern';
    if (diffDays <= 7) return `vor ${diffDays} Tagen`;
    return date.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' });
  };

  const formatKilometer = (value: string | number): string | null => {
    if (value === undefined || value === null || value === '') return null;
    const num = Number(String(value).replace(/[^0-9.,]/g, '').replace(',', '.'));
    if (Number.isNaN(num) || num <= 0) return null;
    if (num >= 1000) {
      const tkm = Math.round(num / 1000);
      return `${tkm} Tkm`;
    }
    return `${Math.round(num)} km`;
  };

  const truncateTitle = (title: string, maxLength: number = 40) => {
    if (!title || title.trim() === '') return 'Kein Titel verfügbar';
    if (title.length <= maxLength) return title;
    return title.substring(0, maxLength).trim() + '...';
  };

  const handleMouseEnter = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsHovering(true);
    if (displayImages.length > 1) {
      setCurrentImageIndex(1);
      // Starte automatisches Wechseln der Bilder beim Hover (Avito-ähnlich)
      if (!hoverIntervalRef.current) {
        hoverIntervalRef.current = window.setInterval(() => {
          setCurrentImageIndex((prev) => (prev + 1) % displayImages.length);
        }, 900);
      }
    }
  };

  const handleMouseLeave = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsHovering(false);
    setCurrentImageIndex(0);
    if (hoverIntervalRef.current) {
      window.clearInterval(hoverIntervalRef.current);
      hoverIntervalRef.current = null;
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    e.preventDefault();
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const imageIndex = Math.floor((x / rect.width) * displayImages.length);
    const clampedIndex = Math.max(0, Math.min(imageIndex, displayImages.length - 1));

    if (clampedIndex !== currentImageIndex) {
      setCurrentImageIndex(clampedIndex);
    }
    // Bei aktiver Mausbewegung Autoplay stoppen, um direkte Kontrolle zu geben
    if (hoverIntervalRef.current) {
      window.clearInterval(hoverIntervalRef.current);
      hoverIntervalRef.current = null;
    }
  };

  // Clean-up bei Unmount
  React.useEffect(() => {
    return () => {
      if (hoverIntervalRef.current) {
        window.clearInterval(hoverIntervalRef.current);
        hoverIntervalRef.current = null;
      }
    };
  }, []);

  return (
    <Box
      sx={{
        position: 'relative',
        bgcolor: '#ffffff',
