        },
        '&:active': {
          transition: 'all 0.1s ease'
        },
        '& .MuiIconButton-root': {
          minWidth: { xs: '44px', sm: '28px' },
          minHeight: { xs: '44px', sm: '28px' },
          width: { xs: '44px', sm: '28px' },
          height: { xs: '44px', sm: '28px' },
        }
      }}
      onClick={handleCardClick}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onMouseMove={handleMouseMove}
    >
      {/* Verkäufer-Badge oberhalb der Karte (verdeckt das Bild nicht) */}
      {seller && (
        <Box
          sx={{
            position: 'absolute',
            top: -10,
            left: 12,
            display: 'flex',
            alignItems: 'center',
            gap: 0.5,
            px: 0.5,
            py: 0.25,
            backgroundColor: 'rgba(255,255,255,0.8)',
            border: '1px solid',
            borderColor: 'divider',
            borderRadius: '4px',
            boxShadow: 'none',
            zIndex: 5,
            pointerEvents: 'none'
          }}
        >
          <Avatar
            src={seller.avatar ? (seller.avatar.startsWith('http') ? seller.avatar : `http://localhost:8000/${seller.avatar.startsWith('/') ? seller.avatar.slice(1) : seller.avatar}`) : undefined}
