          {/* Verkäufername ausgeschrieben */}
          <Typography
            variant="caption"
            sx={{
              fontWeight: 600,
              fontSize: '0.625rem',
              color: 'text.primary',
              maxWidth: 120,
              whiteSpace: 'nowrap',
              overflow: 'hidden',
              textOverflow: 'ellipsis'
            }}
          >
            {seller.name}
