              {seller.rating}
            </Typography>
          </Box>
        </Box>
      )}
      {/* Auf dem Bild keine zusätzlichen Overlays mehr */}

      {/* Image Container */}
      <Box 
        sx={{ 
          position: 'relative', 
          overflow: 'hidden',
          height: '260px',
          minHeight: '260px',
          maxHeight: '260px',
          backgroundColor: '#ffffff',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
          cursor: 'pointer'
        }}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        onMouseMove={handleMouseMove}
      >
        {/* Hauptbild */}
        <img
