                  border: '1px solid rgba(0, 0, 0, 0.2)',
                  transition: 'all 0.2s ease',
                  cursor: 'pointer',
                  '&:hover': {
                    backgroundColor: index === currentImageIndex ? 'white' : 'rgba(255, 255, 255, 0.8)'
                  }
                }}
                onClick={(e) => {
                  e.stopPropagation();
                  setCurrentImageIndex(index);
                }}
              />
            ))}
          </Box>
        )}

        {/* Kein Verkäufer-Overlay mehr im Bild */}

        {/* Keine Overlays, nur das Bild */}
      </Box>

      {/* Text Container */}
      <Box
        sx={{
          padding: { xs: '10px', sm: '12px' },
          backgroundColor: '#ffffff',
