            {formatPrice(price)}
          </Typography>

          {/* Icons rechts */}
          <Box sx={{ display: 'flex', gap: 0.25 }}>
            {/* Favorite Button */}
            <IconButton
              onClick={handleFavoriteToggle}
              disabled={isLoading}
              size="small"
              sx={{
                width: 24,
                height: 24,
