      </Box>

      {/* Menu */}
      <Menu
        anchorEl={anchorEl}
        open={open}
        onClose={handleMenuClose}
        PaperProps={{
          sx: {
            borderRadius: '12px',
            boxShadow: '0 8px 25px rgba(0, 0, 0, 0.15)',
            border: '1px solid #f0f0f0'
          }
        }}
      >
        <MenuItem onClick={handleShare}>
                          <Box sx={{ mr: 1, fontSize: 18 }}>
                  <ShareIcon />
                </Box>
          Teilen
        </MenuItem>
        <MenuItem onClick={handleReport}>
          <Report sx={{ mr: 1, fontSize: 18 }} />
          Melden
        </MenuItem>
        {user?.role === 'admin' && (
          <MenuItem onClick={() => { setAdminEditOpen(true); handleMenuClose(); }}>
            <Edit sx={{ mr: 1, fontSize: 18 }} />
            Bearbeiten
          </MenuItem>
        )}
      </Menu>

      {/* Admin Edit Dialog */}
      {adminEditOpen && (
        <AdminListingEdit
          listingId={parseInt(id)}
          open={adminEditOpen}
          onClose={() => setAdminEditOpen(false)}
        />
      )}
    </Box>
  );
};

