// Smooth Transition Komponenten
export const SlideTransition: React.FC<{
  children: React.ReactNode;
  direction?: 'up' | 'down' | 'left' | 'right';
  in?: boolean;
  timeout?: number;
}> = ({ children, direction = 'up', in: inProp = true, timeout = 300 }) => (
  <Slide direction={direction} in={inProp} timeout={timeout}>
    <Box>{children}</Box>
  </Slide>
);

export const FadeTransition: React.FC<{
  children: React.ReactNode;
  in?: boolean;
  timeout?: number;
}> = ({ children, in: inProp = true, timeout = 300 }) => (
  <Fade in={inProp} timeout={timeout}>
    <Box>{children}</Box>
  </Fade>
);

export const ZoomTransition: React.FC<{
  children: React.ReactNode;
  in?: boolean;
  timeout?: number;
}> = ({ children, in: inProp = true, timeout = 300 }) => (
  <Zoom in={inProp} timeout={timeout}>
    <Box>{children}</Box>
  </Zoom>
);

// Animated Search Bar
export const AnimatedSearchBar: React.FC<{
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  onSearch?: () => void;
  suggestions?: string[];
  onSuggestionClick?: (suggestion: string) => void;
}> = ({ 
  value, 
  onChange, 
  placeholder = "Suchen...", 
  onSearch,
  suggestions = [],
  onSuggestionClick
}) => {
  const theme = useTheme();
  const [isFocused, setIsFocused] = React.useState(false);
  const [showSuggestions, setShowSuggestions] = React.useState(false);

  return (
    <Box sx={{ position: 'relative', width: '100%' }}>
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          border: '2px solid',
          borderColor: isFocused ? 'primary.main' : 'divider',
          borderRadius: 2,
          p: 1,
          transition: 'all 0.3s ease',
          backgroundColor: '#ffffff',
          '&:hover': {
            borderColor: 'primary.main',
            boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
          }
        }}
      >
        <SearchIcon 
          sx={{ 
            mr: 1, 
            color: isFocused ? 'primary.main' : 'text.secondary',
            transition: 'color 0.3s ease'
          }} 
        />
        <input
          type="text"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onFocus={() => {
            setIsFocused(true);
            setShowSuggestions(true);
          }}
          onBlur={() => {
            setIsFocused(false);
            // Verzögerung für Klick-Events
            setTimeout(() => setShowSuggestions(false), 200);
          }}
          placeholder={placeholder}
          style={{
            border: 'none',
            outline: 'none',
            flex: 1,
            fontSize: '16px',
            backgroundColor: 'transparent'
          }}
        />
        {value && (
          <FadeTransition in={!!value}>
            <IconButton
              size="small"
              onClick={() => onChange('')}
              sx={{ ml: 1 }}
            >
              <CloseIcon fontSize="small" />
            </IconButton>
          </FadeTransition>
        )}
        {onSearch && (
          <Button
            variant="contained"
            onClick={onSearch}
            sx={{ ml: 1, borderRadius: 1 }}
          >
            Suchen
          </Button>
        )}
      </Box>
      
      {/* Animated Suggestions */}
      <Collapse in={showSuggestions && suggestions.length > 0}>
        <Box
          sx={{
            position: 'absolute',
            top: '100%',
            left: 0,
            right: 0,
            zIndex: 1000,
            mt: 1,
            bgcolor: '#ffffff',
            borderRadius: 2,
            boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
            border: '1px solid',
            borderColor: 'divider'
          }}
        >
          {suggestions.map((suggestion, index) => (
            <Grow in={showSuggestions} timeout={index * 100} key={suggestion}>
              <Box
                sx={{
                  p: 2,
                  cursor: 'pointer',
                  '&:hover': {
                    backgroundColor: 'action.hover'
                  },
                  borderBottom: index < suggestions.length - 1 ? '1px solid' : 'none',
                  borderColor: 'divider'
                }}
                onClick={() => onSuggestionClick?.(suggestion)}
              >
                <Typography variant="body2">{suggestion}</Typography>
              </Box>
            </Grow>
          ))}
        </Box>
      </Collapse>
    </Box>
  );
};

