import React, { useState, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Box, Typography, CircularProgress } from '@mui/material';
import './CategoryCards.css'; // Import the CSS file

// Kategorie-Daten
interface Category {
  id: number;
  name: string;
  slug: string;
  icon: string;
  color: string;
  bgColor: string;
}

interface CategoryCardsProps {
  theme: 'kleinanzeigen' | 'autos';
}

export const CategoryCards: React.FC<CategoryCardsProps> = ({ theme }) => {
  const navigate = useNavigate();
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Kategorien vom Backend laden
  useEffect(() => {
    const fetchCategories = async () => {
      try {
        setLoading(true);
        const response = await fetch(`http://localhost:8000/api/categories/all`);
        if (!response.ok) {
          throw new Error('Fehler beim Laden der Kategorien');
        }
        const data = await response.json();

        // Konvertiere Backend-Format zu Frontend-Format
        const convertedCategories = data.map((cat: any) => ({
          id: cat.id,
          name: cat.label,
          slug: cat.value,
          icon: cat.icon,
          color: '#059669',
          bgColor: '#f0fdf4'
        }));

        setCategories(convertedCategories);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Unbekannter Fehler');
        console.error('Fehler beim Laden der Kategorien:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchCategories();
  }, [theme]);

  const handleCategoryClick = useCallback((category: Category) => {
    navigate(`/category/${category.slug}`);
  }, [navigate]);

  const getCategoryIcon = useCallback((category: Category): string => {
    // Verwende das Icon vom Backend (Emoji)
    return category.icon || '📦';
  }, []);

  return (
    <Box sx={{ width: '100%' }}>
      {loading ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
          <CircularProgress />
        </Box>
      ) : error ? (
        <Box sx={{ textAlign: 'center', p: 4 }}>
          <Typography color="error">{error}</Typography>
        </Box>
      ) : (
        <Box
          sx={{
            // Mobile: horizontale Scroll-Leiste mit Snap
            display: { xs: 'flex', sm: 'grid' },
            overflowX: { xs: 'auto', sm: 'visible' },
            scrollSnapType: { xs: 'x mandatory', sm: 'none' },
            WebkitOverflowScrolling: { xs: 'touch', sm: 'auto' },
            px: { xs: 0.5, sm: 1 }, // Reduziert von 1/2 auf 0.5/1 für kompakteres Layout
            gap: 1, // Reduziert von 1.5 auf 1 für kompakteres Layout
            '&::-webkit-scrollbar': { display: { xs: 'none', sm: 'initial' } },
            scrollbarWidth: { xs: 'none', sm: 'auto' },
            msOverflowStyle: { xs: 'none', sm: 'auto' },
            // Desktop: Grid
            gridTemplateColumns: {
              sm: 'repeat(4, 1fr)',
              md: 'repeat(5, 1fr)',
              lg: 'repeat(7, 1fr)',
              xl: 'repeat(9, 1fr)'
            }
          }}
        >
          {categories.map((category) => (
            <Box
              key={category.id}
              onClick={() => handleCategoryClick(category)}
              sx={{
                // Mobile: fixe Kartenbreite zum Wischen, Snap-Anker
                flex: { xs: '0 0 auto', sm: 'initial' },
                width: { xs: 120, sm: 'auto' }, // Reduziert von 140px auf 120px
                scrollSnapAlign: { xs: 'start', sm: 'unset' },
                backgroundColor: '#ffffff',
                borderRadius: '8px',
                border: '1px solid #e0e0e0',
                p: 0.75, // Reduziert von 1 auf 0.75 für noch dünnere Karten
                cursor: 'pointer',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'space-between',
                minHeight: '100px', // Kompaktere Höhe für Emoji-Karten
                maxHeight: '100px',
                height: '100px',
                transition: 'all 0.2s ease',
                '&:hover': {
                  borderColor: '#059669',
                  boxShadow: '0 1px 4px rgba(5, 150, 105, 0.08)' /* Weniger Schatten */
                }
              }}
            >
              {/* Category Icon - Emoji vom Backend */}
              <Box
                sx={{
                  fontSize: '48px', // Große Emoji-Größe
                  mt: 0.125,
                  mb: 0.125,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  height: '50px', // Feste Höhe für Emoji
                  filter: 'drop-shadow(0 1px 2px rgba(0,0,0,0.1))'
                }}
              >
                {getCategoryIcon(category)}
              </Box>

              {/* Category Name - Noch kompakter für größere Bilder */}
              <Typography
                variant="body2"
                sx={{
                  fontSize: '0.6rem', // Reduziert von 0.65rem auf 0.6rem
                  fontWeight: 500,
                  textAlign: 'center',
                  color: '#333333',
                  lineHeight: 1.0,
                  maxWidth: '100%',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  mb: 0.125, // Reduziert von 0.25 auf 0.125
                  px: 0.125 // Reduziert von 0.25 auf 0.125
                }}
              >
                {category.name}
              </Typography>
            </Box>
          ))}
        </Box>
      )}
    </Box>
  );
};

import React, { useState, useEffect } from 'react';
import {
  List,
  ListItem,
  ListItemButton,
  ListItemAvatar,
  ListItemText,
