import React, { useState } from 'react';
import { 
  Box, 
  Typography, 
  TextField, 
  Button, 
  Container, 
  Paper, 
  Divider,
  Card,
  CardContent,
  IconButton,
  Chip,
  Avatar,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  RadioGroup,
  FormControlLabel,
  Radio,
  FormLabel,
  Switch,
  InputAdornment,
  Alert,
  Snackbar,
  CircularProgress
} from '@mui/material';
import {
  PhotoCamera as PhotoCameraIcon,
  LocationOn as LocationIcon,
  Person as PersonIcon,
  Favorite as FavoriteIcon,
  Share as ShareIcon,
  MoreVert as MoreVertIcon,
  Visibility as VisibilityIcon,
  CheckCircle as CheckCircleIcon
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { useUser } from '@/context/UserContext';

const CreateListing2: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useUser();

  // Einzelne State-Variablen für bessere Performance
  const [title, setTitle] = useState('iPhone 12 verkaufen');
  const [description, setDescription] = useState('');
  const [price, setPrice] = useState('');
  const [listingType, setListingType] = useState('offer');
  const [priceType, setPriceType] = useState('fixed');
  const [postalCode, setPostalCode] = useState('');
  const [city, setCity] = useState('');
  const [street, setStreet] = useState('');
  const [showFullAddress, setShowFullAddress] = useState(false);
  const [contactName, setContactName] = useState('test');
  const [contactEmail, setContactEmail] = useState('test@example.com');
  const [acceptTerms, setAcceptTerms] = useState(false);
  const [acceptMarketing, setAcceptMarketing] = useState(false);
  const [category, setCategory] = useState('jobs');
  const [images, setImages] = useState<File[]>([]);

  // Backend-Integration States
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  // Backend-Funktionen
  const uploadImages = async (): Promise<string[]> => {
    const uploadedUrls: string[] = [];

    for (const image of images) {
      const formData = new FormData();
      formData.append('file', image);

      try {
        const response = await fetch('http://localhost:8000/api/upload-image', {
          method: 'POST',
          body: formData,
        });

        if (response.ok) {
          const data = await response.json();
          const imageUrl = data.url || data.filename || `http://localhost:8000/api/images/${data.filename}`;
          uploadedUrls.push(imageUrl);
        } else {
          console.error('Error uploading image:', response.statusText);
        }
      } catch (error) {
        console.error('Error uploading image:', error);
      }
    }

    return uploadedUrls;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!acceptTerms) {
      setError('Bitte akzeptieren Sie die Nutzungsbedingungen');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      // Bilder hochladen
      const imageUrls = await uploadImages();

      // Listing erstellen
      const listingData = {
        title: title,
        description: description,
        category: category,
        condition: 'Gebraucht',
        location: `${postalCode} ${city}`,
        price: priceType === 'free' ? 0 : parseFloat(price),
        priceType: priceType,
        listingType: listingType,
        images: imageUrls,
        attributes: {
          showFullAddress: showFullAddress,
          street: street
        },
        contact: {
          name: contactName,
          email: contactEmail
        }
      };

      const response = await fetch('http://localhost:8000/api/listings', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(listingData)
      });

      if (response.ok) {
        setSuccess(true);
        setTimeout(() => {
          navigate('/');
        }, 2000);
      } else {
        const errorData = await response.json();
        setError(errorData.detail || 'Fehler beim Erstellen der Anzeige');
      }
    } catch (error) {
      console.error('Error creating listing:', error);
      setError('Fehler beim Erstellen der Anzeige');
    } finally {
      setLoading(false);
    }
  };

  // Bild-Upload Funktionen
  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(event.target.files || []);
    if (files.length + images.length > 20) {
      console.error('Maximal 20 Bilder erlaubt');
      return;
    }

    const validFiles = files.filter(file => {
      if (file.size > 12 * 1024 * 1024) {
        console.error(`Bild ${file.name} ist zu groß (max. 12MB)`);
        return false;
      }
      return true;
    });

    setImages(prev => [...prev, ...validFiles]);
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  // Breadcrumb Navigation Funktion
  const getCategoryBreadcrumb = (categoryValue: string) => {
    // Demo-Kategorien für Breadcrumb
    const categoryMap: { [key: string]: { label: string; icon: string } } = {
      'jobs': { label: 'Jobs', icon: '💼' },
      'electronics': { label: 'Elektronik', icon: '📱' },
      'vehicles': { label: 'Fahrzeuge', icon: '🚗' },
      'real-estate': { label: 'Immobilien', icon: '🏠' },
      'services': { label: 'Dienstleistungen', icon: '🔧' }
    };

    const categoryObj = categoryMap[categoryValue] || { label: 'Kategorie', icon: '📁' };

    return (
      <Box sx={{ 
        display: 'flex', 
        alignItems: 'center', 
        gap: 1, 
        mb: 2, 
        flexWrap: 'wrap',
        fontSize: '14px',
        color: 'text.secondary',
        borderBottom: '1px solid',
        borderColor: 'divider',
        pb: 1
      }}>
        <span style={{ marginRight: 4 }}>{categoryObj.icon}</span>
        <Typography variant="body2" color="text.secondary">
          {categoryObj.label}
        </Typography>
        <Typography variant="body2" color="text.secondary">
          &gt;
        </Typography>
        <Typography variant="body2" color="text.secondary">
          Ich suche Mitarbeiter
        </Typography>
        <Typography variant="body2" color="text.secondary">
          &gt;
        </Typography>
        <Button 
          variant="text" 
          size="small" 
          onClick={() => navigate('/category-selection')}
          sx={{ 
            minWidth: 'auto',
            p: 0,
            textTransform: 'none',
            fontSize: '14px',
            color: 'primary.main',
            fontWeight: 500,
            '&:hover': {
              backgroundColor: 'transparent',
              textDecoration: 'underline'
            }
          }}
        >
          Kategorie ändern
        </Button>
      </Box>
    );
  };

  // Live-Vorschau der Anzeige
  const LivePreview = () => (
    <Paper elevation={2} sx={{ p: 3, borderRadius: 3, bgcolor: 'white' }}>
      <Typography variant="h6" sx={{ mb: 3, fontWeight: 600, color: 'text.primary', display: 'flex', alignItems: 'center' }}>
        <VisibilityIcon sx={{ mr: 1, color: 'primary.main' }} />
        Live-Vorschau
      </Typography>

      {/* Anzeigen-Karte */}
      <Card elevation={1} sx={{ borderRadius: 2, overflow: 'hidden' }}>
        {/* Hauptbild */}
        <Box sx={{ 
          height: 200, 
          bgcolor: 'grey.100', 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'center',
          position: 'relative'
        }}>
          <PhotoCameraIcon sx={{ fontSize: 48, color: 'grey.400' }} />

          {/* Typ-Badge */}
          <Box sx={{
            position: 'absolute',
            top: 8,
            left: 8,
            bgcolor: listingType === 'offer' ? 'success.main' : 'warning.main',
            color: 'white',
            px: 1.5,
