import {
  PhotoCamera as PhotoCameraIcon,
  LocationOn as LocationIcon,
  Person as PersonIcon,
  Favorite as FavoriteIcon,
  Share as ShareIcon,
  MoreVert as MoreVertIcon,
  Visibility as VisibilityIcon,
  CheckCircle as CheckCircleIcon
} from '@mui/icons-material';
import { useNavigate, useParams } from 'react-router-dom';
import { useUser } from '@/context/UserContext';

const EditListing: React.FC = () => {
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const { user } = useUser();

  // Einzelne State-Variablen für bessere Performance (wie CreateListing)
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [price, setPrice] = useState('');
  const [listingType, setListingType] = useState('offer');
  const [priceType, setPriceType] = useState('fixed');
  const [postalCode, setPostalCode] = useState('');
  const [city, setCity] = useState('');
  const [street, setStreet] = useState('');
  const [showFullAddress, setShowFullAddress] = useState(false);
  const [contactName, setContactName] = useState('');
  const [contactEmail, setContactEmail] = useState('');
  const [acceptTerms, setAcceptTerms] = useState(true);
  const [acceptMarketing, setAcceptMarketing] = useState(false);
  const [category, setCategory] = useState('jobs');
  const [images, setImages] = useState<File[]>([]);
  const [existingImages, setExistingImages] = useState<string[]>([]);

  // Backend-Integration States
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  // Listing beim Laden abrufen
  useEffect(() => {
    if (id) {
      fetchListing();
    }
  }, [id]);

  const fetchListing = async () => {
    try {
      setFetching(true);
      const response = await fetch(`http://localhost:8000/api/listings/${id}`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });

      if (response.ok) {
        const listing = await response.json();

        // Formular mit bestehenden Daten füllen
        setTitle(listing.title || '');
        setDescription(listing.description || '');
        setPrice(listing.price?.toString() || '');
        setListingType(listing.listingType || 'offer');
        setPriceType(listing.priceType || 'fixed');
        setCategory(listing.category || 'jobs');
        setContactName(listing.contact?.name || '');
        setContactEmail(listing.contact?.email || '');
        setShowFullAddress(listing.attributes?.showFullAddress || false);
        setStreet(listing.attributes?.street || '');

        // Standort aufteilen
        if (listing.location) {
          const parts = listing.location.split(' ');
          if (parts.length >= 2) {
            setPostalCode(parts[0]);
            setCity(parts.slice(1).join(' '));
          }
        }

        // Bestehende Bilder setzen
        if (listing.images && Array.isArray(listing.images)) {
          setExistingImages(listing.images);
        }
      } else {
        setError('Listing konnte nicht geladen werden');
      }
    } catch (error) {
      setError('Fehler beim Laden des Listings');
    } finally {
      setFetching(false);
    }
  };

  // Backend-Funktionen
  const uploadImages = async (): Promise<string[]> => {
    const uploadedUrls: string[] = [];

    for (const image of images) {
      const formData = new FormData();
      formData.append('file', image);

      try {
        const response = await fetch('http://localhost:8000/api/upload-image', {
          method: 'POST',
          body: formData,
        });

        if (response.ok) {
          const data = await response.json();
          const imageUrl = data.url || data.filename || `http://localhost:8000/api/images/${data.filename}`;
          uploadedUrls.push(imageUrl);
        } else {
          console.error('Error uploading image:', response.statusText);
        }
      } catch (error) {
        console.error('Error uploading image:', error);
      }
    }

    return uploadedUrls;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!acceptTerms) {
      setError('Bitte akzeptieren Sie die Nutzungsbedingungen');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      // Neue Bilder hochladen
      const newImageUrls = await uploadImages();

      // Alle Bilder kombinieren (bestehende + neue)
      const allImages = [...existingImages, ...newImageUrls];

      // Listing aktualisieren
      const listingData = {
        title: title,
        description: description,
        category: category,
        condition: 'Gebraucht',
        location: `${postalCode} ${city}`,
        price: priceType === 'free' ? 0 : parseFloat(price),
        priceType: priceType,
        listingType: listingType,
        images: allImages,
        attributes: {
          showFullAddress: showFullAddress,
          street: street
        },
        contact: {
          name: contactName,
          email: contactEmail
        }
      };

      const response = await fetch(`http://localhost:8000/api/listings/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(listingData)
      });

      if (response.ok) {
        setSuccess(true);
        setTimeout(() => {
          navigate(`/listing/${id}`);
        }, 2000);
      } else {
        const errorData = await response.json();
        setError(errorData.detail || 'Fehler beim Aktualisieren der Anzeige');
      }
    } catch (error) {
      console.error('Error updating listing:', error);
      setError('Fehler beim Aktualisieren der Anzeige');
    } finally {
      setLoading(false);
    }
  };

  // Bild-Upload Funktionen
  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(event.target.files || []);
    if (files.length + images.length > 20) {
      console.error('Maximal 20 Bilder erlaubt');
      return;
    }

    const validFiles = files.filter(file => {
      if (file.size > 12 * 1024 * 1024) {
        console.error(`Bild ${file.name} ist zu groß (max. 12MB)`);
        return false;
      }
      return true;
    });

    setImages(prev => [...prev, ...validFiles]);
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const removeExistingImage = (index: number) => {
    setExistingImages(prev => prev.filter((_, i) => i !== index));
  };

  // Breadcrumb Navigation Funktion
  const getCategoryBreadcrumb = (categoryValue: string) => {
    const categoryMap: { [key: string]: { label: string; icon: string } } = {
      'jobs': { label: 'Jobs', icon: '💼' },
      'electronics': { label: 'Elektronik', icon: '📱' },
      'vehicles': { label: 'Fahrzeuge', icon: '🚗' },
      'real-estate': { label: 'Immobilien', icon: '🏠' },
      'services': { label: 'Dienstleistungen', icon: '🔧' }
    };

    const categoryObj = categoryMap[categoryValue] || { label: 'Kategorie', icon: '📁' };

    return (
      <Box sx={{ 
        display: 'flex', 
        alignItems: 'center', 
        gap: 1, 
        mb: 2, 
        flexWrap: 'wrap',
        fontSize: '14px',
        color: 'text.secondary',
        borderBottom: '1px solid',
        borderColor: 'divider',
        pb: 1
      }}>
        <span style={{ marginRight: 4 }}>{categoryObj.icon}</span>
        <Typography variant="body2" color="text.secondary">
          {categoryObj.label}
        </Typography>
        <Typography variant="body2" color="text.secondary">
          &gt;
        </Typography>
        <Typography variant="body2" color="text.secondary">
          Ich suche Mitarbeiter
        </Typography>
        <Typography variant="body2" color="text.secondary">
          &gt;
        </Typography>
        <Button 
          variant="text" 
          size="small" 
          onClick={() => navigate('/category-selection')}
          sx={{ 
            minWidth: 'auto',
            p: 0,
            textTransform: 'none',
            fontSize: '14px',
            color: 'primary.main',
            fontWeight: 500,
            '&:hover': {
              backgroundColor: 'transparent',
              textDecoration: 'underline'
            }
          }}
        >
          Kategorie ändern
        </Button>
      </Box>
    );
  };

  // Live-Vorschau der Anzeige
  const LivePreview = () => (
    <Paper elevation={2} sx={{ p: 3, borderRadius: 3, bgcolor: 'white' }}>
      <Typography variant="h6" sx={{ mb: 3, fontWeight: 600, color: 'text.primary', display: 'flex', alignItems: 'center' }}>
        <VisibilityIcon sx={{ mr: 1, color: 'primary.main' }} />
        Live-Vorschau
      </Typography>

      <Card elevation={1} sx={{ borderRadius: 2, overflow: 'hidden' }}>
        <Box sx={{ 
          height: 200, 
          bgcolor: 'grey.100', 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'center',
          position: 'relative'
        }}>
          <PhotoCameraIcon sx={{ fontSize: 48, color: 'grey.400' }} />

          <Box sx={{
            position: 'absolute',
            top: 8,
            left: 8,
            bgcolor: listingType === 'offer' ? 'success.main' : 'warning.main',
            color: 'white',
            px: 1.5,
            py: 0.5,
            borderRadius: 1,
            fontSize: '0.75rem',
            fontWeight: 600
          }}>
            {listingType === 'offer' ? 'Ich biete' : 'Ich suche'}
          </Box>
        </Box>

        <CardContent sx={{ p: 2 }}>
          <Typography variant="h6" sx={{ 
            fontWeight: 600, 
            color: 'text.primary',
            mb: 1,
            minHeight: 24,
            ...(title ? {} : { color: 'text.disabled', fontStyle: 'italic' })
          }}>
            {title || 'Titel der Anzeige'}
          </Typography>

          <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
            <Typography variant="h5" sx={{ 
              fontWeight: 700, 
              color: 'primary.main',
              mr: 1
            }}>
              {priceType === 'free' ? 'Zu verschenken' : 
               price ? `${price} EUR` : 'Preis'}
            </Typography>
            {priceType === 'negotiable' && (
              <Chip label="VB" size="small" color="warning" variant="outlined" />
            )}
          </Box>

          <Typography variant="body2" sx={{ 
            color: 'text.secondary',
            mb: 2,
            minHeight: 40,
            ...(description ? {} : { color: 'text.disabled', fontStyle: 'italic' })
          }}>
            {description || 'Beschreibung der Anzeige...'}
          </Typography>

          {(postalCode || city) && (
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
              <LocationIcon sx={{ fontSize: 16, color: 'text.secondary', mr: 0.5 }} />
              <Typography variant="body2" color="text.secondary">
                {postalCode} {city}
              </Typography>
            </Box>
          )}

          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <Box sx={{ display: 'flex', gap: 1 }}>
              <IconButton size="small" sx={{ color: 'text.secondary' }}>
                <FavoriteIcon />
              </IconButton>
              <IconButton size="small" sx={{ color: 'text.secondary' }}>
                <ShareIcon />
              </IconButton>
            </Box>
            <IconButton size="small" sx={{ color: 'text.secondary' }}>
              <MoreVertIcon />
            </IconButton>
          </Box>
        </CardContent>
      </Card>
    </Paper>
  );

  if (fetching) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '400px' }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Container maxWidth="xl" sx={{ py: { xs: 2, md: 4 } }}>
      {/* Header */}
      <Box sx={{ mb: 4, textAlign: 'center' }}>
        <Typography
          variant="h3"
          component="h1"
          gutterBottom
          sx={{
            fontWeight: 700,
            color: 'text.primary',
            mb: 2
          }}
        >
          Anzeige bearbeiten
        </Typography>
        <Typography
          variant="h6"
          color="text.secondary"
          sx={{ mb: 3 }}
        >
          Bearbeite deine Anzeige mit Live-Vorschau
        </Typography>
      </Box>

      {/* Hauptinhalt - 2-Spalten Layout */}
      <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', lg: '1fr 400px' }, gap: 4 }}>
        {/* Linke Spalte - Formular */}
        <Paper elevation={0} sx={{ p: 4, borderRadius: 3, border: '1px solid', borderColor: 'divider' }}>
          <form onSubmit={handleSubmit}>
            {/* Grundlegende Informationen */}
            <Typography variant="h5" sx={{ mb: 3, fontWeight: 600, color: 'text.primary' }}>
              Grundinformationen
            </Typography>

            {/* Gebot/Gesuch */}
            <Box sx={{ mb: 4 }}>
              <FormLabel component="legend" sx={{ mb: 2, fontWeight: 600, color: 'text.primary' }}>
                Gebot / Gesuch
              </FormLabel>
              <RadioGroup
                row
                value={listingType}
                onChange={(e) => setListingType(e.target.value)}
              >
                <FormControlLabel
                  value="offer"
                  control={<Radio sx={{ color: 'primary.main' }} />}
                  label="Ich biete"
                  sx={{ mr: 4 }}
                />
                <FormControlLabel
                  value="request"
                  control={<Radio sx={{ color: 'primary.main' }} />}
                  label="Ich suche"
                />
              </RadioGroup>
            </Box>

            {/* Titel */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Typography sx={{ pt: 2, fontWeight: 500, fontSize: '0.875rem' }}>
                  Titel
                </Typography>
                <Box sx={{ width: '100%' }}>
                  <TextField
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    required
                    sx={{ width: '100%' }}
                  />
                  {/* Breadcrumb Navigation unter dem Titel */}
                  {getCategoryBreadcrumb(category)}
                </Box>
                <Box sx={{ color: 'text.secondary', pt: 2 }}>
                  <Typography variant="caption">
                    <strong>Tipp:</strong> Mit einem aussagekräftigen Titel verkaufst du besser.
                  </Typography>
                </Box>
              </Box>
            </Box>

            {/* Preis */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Typography sx={{ pt: 2, fontWeight: 500, fontSize: '0.875rem' }}>
                  Preis
                </Typography>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, width: '100%' }}>
                  <TextField
                    type="number"
                    value={price}
                    onChange={(e) => setPrice(e.target.value)}
                    required={priceType !== 'free'}
                    disabled={priceType === 'free'}
                    sx={{ width: '120px' }}
                  />
                  <Typography variant="body1" sx={{ color: 'text.secondary', fontWeight: 500 }}>
                    ,00 EUR
                  </Typography>
                  <FormControl sx={{ width: '150px' }}>
                    <Select
                      value={priceType}
                      onChange={(e) => setPriceType(e.target.value)}
                    >
                      <MenuItem value="fixed">Festpreis</MenuItem>
                      <MenuItem value="negotiable">Verhandlungsbasis</MenuItem>
                      <MenuItem value="free">Zu verschenken</MenuItem>
                    </Select>
                  </FormControl>
                </Box>
                <Box></Box>
              </Box>
            </Box>

            {/* Beschreibung */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Typography sx={{ pt: 2, fontWeight: 500, fontSize: '0.875rem' }}>
                  Beschreibung
                </Typography>
                <TextField
                  multiline
                  rows={6}
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  required
                  helperText={`${description.length}/4000 Zeichen`}
                  inputProps={{ maxLength: 4000 }}
                  sx={{ width: '100%' }}
                />
                <Box></Box>
              </Box>
            </Box>

            {/* Bilder */}
            <Typography variant="h6" sx={{ mb: 2, fontWeight: 600, color: 'text.primary' }}>
              Bilder (empfohlen)
            </Typography>

            <Box sx={{ 
              display: 'grid', 
              gridTemplateColumns: '10% 60% 30%', 
              gap: 2, 
              alignItems: 'flex-start' 
            }}>
              <Box></Box>
              <Box sx={{ width: '100%' }}>
                {/* Bestehende Bilder */}
                {existingImages.length > 0 && (
                  <Box sx={{ mb: 2 }}>
                    <Typography variant="subtitle2" sx={{ mb: 1 }}>
                      Bestehende Bilder:
                    </Typography>
                    <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 2 }}>
                      {existingImages.map((image, index) => (
                        <Box
                          key={index}
                          sx={{
                            position: 'relative',
                            width: 80,
                            height: 80,
                            borderRadius: 1,
                            overflow: 'hidden',
                            border: '1px solid',
                            borderColor: 'grey.300',
                            flexShrink: 0
                          }}
                        >
                          <Box
                            component="img"
                            src={image.startsWith('http') ? image : `http://localhost:8000/api/images/${image}`}
                            alt={`Bild ${index + 1}`}
                            sx={{
                              width: '100%',
                              height: '100%',
                              objectFit: 'cover'
                            }}
                          />
                          <Box
                            onClick={() => removeExistingImage(index)}
                            sx={{
                              position: 'absolute',
                              top: 2,
                              right: 2,
                              bgcolor: 'rgba(0,0,0,0.7)',
                              width: 18,
                              height: 18,
                              borderRadius: '50%',
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              cursor: 'pointer',
                              '&:hover': {
                                bgcolor: 'rgba(0,0,0,0.9)'
                              }
                            }}
                          >
                            <img 
                              src="/src/assets/icons/delete.svg?v=2" 
                              alt="Löschen" 
                              style={{ 
                                width: '16px', 
                                height: '16px', 
                                filter: 'invert(1)',
                                transform: 'scale(1)'
                              }} 
                            />
                          </Box>
                        </Box>
                      ))}
                    </Box>
                  </Box>
                )}

                {/* Bild-Upload und Thumbnails in einer Reihe */}
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 1 }}>
                  {/* Upload-Feld */}
                  <Box
                    sx={{
                      border: '2px dashed',
                      borderColor: 'grey.300',
                      borderRadius: 1,
                      width: 80,
                      height: 80,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      cursor: 'pointer',
                      transition: 'all 0.3s ease',
                      flexShrink: 0,
                      '&:hover': {
                        borderColor: 'primary.main',
                        bgcolor: 'primary.50',
                      }
                    }}
                  >
                    <input
                      type="file"
                      multiple
                      accept="image/*"
                      onChange={handleImageUpload}
                      style={{ display: 'none' }}
                      id="image-upload"
                    />
                    <label htmlFor="image-upload" style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', width: '100%', height: '100%' }}>
                      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column' }}>
                        <PhotoCameraIcon sx={{ fontSize: 20, color: 'grey.500' }} />
                        <Typography sx={{ fontSize: 24, color: 'grey.500', lineHeight: 1 }}>+</Typography>
                      </Box>
                    </label>
                  </Box>

                  {/* Neue Thumbnails */}
                  {images.map((image, index) => (
                    <Box
                      key={index}
                      sx={{
                        position: 'relative',
                        width: 80,
                        height: 80,
                        borderRadius: 1,
                        overflow: 'hidden',
                        border: '1px solid',
                        borderColor: 'grey.300',
                        flexShrink: 0
                      }}
                    >
                      <Box
                        component="img"
                        src={URL.createObjectURL(image)}
                        alt={`Bild ${index + 1}`}
                        sx={{
                          width: '100%',
                          height: '100%',
                          objectFit: 'cover'
                        }}
                      />
                      <Box
                        onClick={() => removeImage(index)}
                        sx={{
                          position: 'absolute',
                          top: 2,
                          right: 2,
                          bgcolor: 'rgba(0,0,0,0.7)',
                          width: 18,
                          height: 18,
                          borderRadius: '50%',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          cursor: 'pointer',
                          '&:hover': {
                            bgcolor: 'rgba(0,0,0,0.9)'
                          }
                        }}
                      >
                        <img 
                          src="/src/assets/icons/delete.svg?v=2" 
                          alt="Löschen" 
                          style={{ 
                            width: '16px', 
                            height: '16px', 
                            filter: 'invert(1)',
                            transform: 'scale(1)'
                          }} 
                        />
                      </Box>
                    </Box>
                  ))}
                </Box>

                {images.length > 0 && (
                  <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                    → Verschieben, um die Reihenfolge zu ändern
                  </Typography>
                )}
              </Box>

              {/* Tipp rechts */}
              <Box sx={{ color: 'text.secondary' }}>
                <Typography variant="caption" sx={{ lineHeight: 1.5 }}>
                  <strong>Tipp:</strong> Füge bis zu 20 Bilder (max. 12 MB) per Upload oder Drag & Drop hinzu. Für bessere Ergebnisse helfen dir unsere{' '}
                  <Button
                    component="a"
                    href="/fototipps"
                    target="_blank"
                    sx={{ p: 0, minWidth: 'auto', textTransform: 'none', fontSize: 'inherit', color: 'primary.main' }}
                  >
                    Fototipps
                  </Button>
                  .
                </Typography>
              </Box>
            </Box>

            {/* Standort */}
            <Typography variant="h5" sx={{ mb: 3, fontWeight: 600, color: 'text.primary' }}>
              Standort
            </Typography>

            {/* PLZ und Stadt */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Typography sx={{ pt: 2, fontWeight: 500, fontSize: '0.875rem' }}>
                  PLZ
                </Typography>
                <Box sx={{ display: 'flex', gap: 2, width: '100%' }}>
                  <TextField
                    value={postalCode}
                    onChange={(e) => setPostalCode(e.target.value)}
                    required
                    sx={{ width: '120px' }}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <LocationIcon color="action" />
                        </InputAdornment>
                      ),
                    }}
                  />
                  <TextField
                    value={city}
                    onChange={(e) => setCity(e.target.value)}
                    required
                    sx={{ width: '200px' }}
                  />
                </Box>
                <Box></Box>
              </Box>
            </Box>

            {/* Straße */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Typography sx={{ pt: 2, fontWeight: 500, fontSize: '0.875rem' }}>
                  Straße/Nr.
                </Typography>
                <TextField
                  value={street}
                  onChange={(e) => setStreet(e.target.value)}
                  sx={{ width: '100%' }}
                />
                <Box sx={{ color: 'text.secondary' }}>
                  <Typography variant="caption">
                    <strong>Tipp:</strong> Standardmäßig zeigen wir nur die Postleitzahl und den Ort an. Wenn du die vollständige Adresse anzeigen lassen möchtest, setze bitte einen Haken im Kasten.
                  </Typography>
                </Box>
              </Box>
            </Box>

            {/* Vollständige Adresse anzeigen */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Box></Box>
                <FormControlLabel
                  control={
                    <Switch
                      checked={showFullAddress}
                      onChange={(e) => setShowFullAddress(e.target.checked)}
                      color="primary"
                    />
                  }
                  label="Vollständige Adresse anzeigen"
                />
                <Box></Box>
              </Box>
            </Box>

            {/* Kontaktdaten */}
            <Typography variant="h5" sx={{ mb: 3, fontWeight: 600, color: 'text.primary' }}>
              Deine Angaben
            </Typography>

            {/* Name */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Typography sx={{ pt: 2, fontWeight: 500, fontSize: '0.875rem' }}>
                  Name
                </Typography>
                <TextField
                  value={contactName}
                  onChange={(e) => setContactName(e.target.value)}
                  required
                  sx={{ width: '200px' }}
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <PersonIcon color="action" />
                      </InputAdornment>
                    ),
                  }}
                />
                <Box sx={{ color: 'text.secondary' }}>
                  <Typography variant="caption">
                    <strong>Tipp:</strong> Du kannst deinen Profilnamen jederzeit in den Einstellungen ändern.
                  </Typography>
                </Box>
              </Box>
            </Box>

            {/* E-Mail */}
            <Box sx={{ mb: 4 }}>
              <Box sx={{ 
                display: 'grid', 
                gridTemplateColumns: '10% 60% 30%', 
                gap: 2, 
                alignItems: 'flex-start' 
              }}>
                <Typography sx={{ pt: 2, fontWeight: 500, fontSize: '0.875rem' }}>
                  E-Mail
                </Typography>
                <TextField
                  value={contactEmail}
                  onChange={(e) => setContactEmail(e.target.value)}
                  required
                  type="email"
                  sx={{ width: '100%' }}
                />
                <Box></Box>
              </Box>
            </Box>

            {/* Submit Buttons */}
            <Box sx={{ display: 'flex', gap: 2, justifyContent: 'flex-end' }}>
              <Button
                variant="outlined"
                onClick={() => navigate(`/listing/${id}`)}
                sx={{ minWidth: 120 }}
              >
                Abbrechen
              </Button>

              <Button
                type="submit"
                variant="contained"
                disabled={!acceptTerms || loading}
                endIcon={loading ? <CircularProgress size={20} /> : <CheckCircleIcon />}
                sx={{ minWidth: 180 }}
              >
                {loading ? 'Wird gespeichert...' : 'Änderungen speichern'}
              </Button>
            </Box>
          </form>
        </Paper>

        {/* Rechte Spalte - Live-Vorschau */}
        <Box sx={{ position: 'sticky', top: 24 }}>
          <LivePreview />
        </Box>
      </Box>

      {/* Error Snackbar */}
      <Snackbar
        open={!!error}
        autoHideDuration={6000}
        onClose={() => setError(null)}
        anchorOrigin={{ vertical: 'top', horizontal: 'center' }}
      >
        <Alert onClose={() => setError(null)} severity="error" sx={{ width: '100%' }}>
          {error}
        </Alert>
      </Snackbar>

      {/* Success Snackbar */}
      <Snackbar
        open={success}
        autoHideDuration={2000}
        onClose={() => setSuccess(false)}
        anchorOrigin={{ vertical: 'top', horizontal: 'center' }}
      >
        <Alert onClose={() => setSuccess(false)} severity="success" sx={{ width: '100%' }}>
          Anzeige erfolgreich aktualisiert! Weiterleitung zur Detailseite...
        </Alert>
      </Snackbar>
    </Container>
  );
};

export default EditListing;

import React, { useState } from 'react';
import {
  Box,
  Paper,
  Typography,
  Button,
  Alert,
  CircularProgress,
  Divider,
  Link
} from '@mui/material';
import { Email, CheckCircle, Error } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';

interface EmailVerificationProps {
  email: string;
  onResendVerification: (email: string) => Promise<void>;
}

export const EmailVerification: React.FC<EmailVerificationProps> = ({
  email,
  onResendVerification
}) => {
  const [isResending, setIsResending] = useState(false);
  const [resendSuccess, setResendSuccess] = useState(false);
  const [resendError, setResendError] = useState<string | null>(null);
  const navigate = useNavigate();

  const handleResendVerification = async () => {
    setIsResending(true);
    setResendError(null);
    setResendSuccess(false);

    try {
      await onResendVerification(email);
      setResendSuccess(true);
    } catch (error: unknown) {
      let errorMessage = 'Fehler beim erneuten Senden der E-Mail';
      if (error && typeof error === 'object' && 'message' in error && typeof error.message === 'string') {
        errorMessage = error.message;
      }
      setResendError(errorMessage);
    } finally {
      setIsResending(false);
    }
  };

  const handleGoToLogin = () => {
    navigate('/login');
  };

  return (
    <Box
      sx={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        minHeight: '100vh',
        bgcolor: '#f5f5f5',
        p: 2
      }}
    >
      <Paper
        elevation={3}
        sx={{
          p: 4,
          maxWidth: 500,
          width: '100%',
          textAlign: 'center'
        }}
      >
        <Box sx={{ mb: 3 }}>
          <Email sx={{ fontSize: 64, color: '#1976d2', mb: 2 }} />
          <Typography variant="h4" component="h1" gutterBottom sx={{ fontWeight: 'bold' }}>
            E-Mail bestätigen
          </Typography>
          <Typography variant="body1" color="text.secondary" sx={{ mb: 2 }}>
            Wir haben eine Bestätigungs-E-Mail an <strong>{email}</strong> gesendet.
          </Typography>
        </Box>

        <Alert severity="info" sx={{ mb: 3, textAlign: 'left' }}>
          <Typography variant="body2">
            <strong>Bitte überprüfen Sie Ihren E-Mail-Eingang und klicken Sie auf den Bestätigungslink.</strong>
          </Typography>
          <Typography variant="body2" sx={{ mt: 1 }}>
            Falls Sie die E-Mail nicht finden, überprüfen Sie auch Ihren Spam-Ordner.
          </Typography>
        </Alert>

        <Divider sx={{ my: 3 }} />

        <Box sx={{ mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Keine E-Mail erhalten?
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Klicken Sie auf den Button unten, um eine neue Bestätigungs-E-Mail zu erhalten.
          </Typography>
          
          <Button
            variant="outlined"
            onClick={handleResendVerification}
            disabled={isResending}
            startIcon={isResending ? <CircularProgress size={20} /> : <Email />}
            sx={{ mb: 2 }}
          >
            {isResending ? 'Wird gesendet...' : 'E-Mail erneut senden'}
          </Button>

          {resendSuccess && (
            <Alert severity="success" sx={{ mt: 2 }}>
              <CheckCircle sx={{ mr: 1 }} />
              Bestätigungs-E-Mail wurde erneut gesendet!
            </Alert>
          )}

          {resendError && (
            <Alert severity="error" sx={{ mt: 2 }}>
              <Error sx={{ mr: 1 }} />
              {resendError}
            </Alert>
          )}
        </Box>

        <Divider sx={{ my: 3 }} />

        <Box>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Bereits bestätigt?
          </Typography>
          <Button
            variant="contained"
            onClick={handleGoToLogin}
            sx={{ 
              bgcolor: '#1976d2',
              '&:hover': { bgcolor: '#1565c0' }
            }}
          >
            Zum Login
          </Button>
        </Box>

        <Box sx={{ mt: 3 }}>
          <Typography variant="caption" color="text.secondary">
            Probleme mit der E-Mail?{' '}
            <Link href="mailto:support@kleinanzeigen.de" underline="hover">
              Kontaktieren Sie unseren Support
            </Link>
          </Typography>
        </Box>
      </Paper>
    </Box>
  );
};

import React from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Card,
  CardContent,
  CardMedia,
  Typography,
  Box,
  Chip,
  Button,
  Avatar,
  Rating,
  Divider,
  IconButton,
  Tooltip,
} from '@mui/material';
import {
  LocationOn,
  Phone,
  Email,
  Language,
  Message,
  Visibility,
  Star,
  Verified,
  WorkspacePremium,
  ThumbUp,
} from '@mui/icons-material';

// Lokale Definitionen um Caching-Probleme zu vermeiden
type EntityType = 'shop' | 'provider' | 'user';

interface EntityRating {
  value: number;
  count: number;
}

interface EntityContact {
  phone?: string;
  email?: string;
  website?: string;
}

interface EntityLinks {
  view?: string;
  message?: string;
}

interface EntityBadges {
  verified?: boolean;
  certified?: boolean;
  recommended?: boolean;
}

interface BaseEntity {
  id: string | number;
  type: EntityType;
  name: string;
  subtitle?: string;
  avatarUrl?: string;
  initials?: string;
  location?: string;
  description?: string;
  tags?: string[];
  rating?: EntityRating;
  badges: EntityBadges;
  contact?: EntityContact;
  links?: EntityLinks;
}

interface ShopEntity extends BaseEntity {
  type: 'shop';
  listingsCount?: number;
  priceFrom?: string;
}

interface ProviderEntity extends BaseEntity {
  type: 'provider';
  experienceYears?: number;
  available?: boolean;
  priceFrom?: string;
}

interface UserEntity extends BaseEntity {
  type: 'user';
  memberSince?: string;
}

type Entity = ShopEntity | ProviderEntity | UserEntity;

interface EntityCardProps {
  entity: Entity;
  onView?: (entity: Entity) => void;
  onMessage?: (entity: Entity) => void;
  onCall?: (entity: Entity) => void;
  onEmail?: (entity: Entity) => void;
  onWebsite?: (entity: Entity) => void;
  onProfile?: (entity: Entity) => void;
}

const EntityCard: React.FC<EntityCardProps> = ({
  entity,
  onView,
  onMessage,
  onCall,
  onEmail,
  onWebsite,
  onProfile,
}) => {
  const navigate = useNavigate();
  const getInitials = (name: string): string => {
    return name
      .split(' ')
      .map(word => word.charAt(0))
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  const getTypeLabel = (type: EntityType): string => {
    switch (type) {
      case 'shop': return 'Shop';
      case 'provider': return 'Dienstleister';
      case 'user': return 'Benutzer';
      default: return 'Unbekannt';
    }
  };

  const getTypeColor = (type: EntityType): string => {
    // Einheitliche graue Farbe für alle Typen
    return '#6b7280';
  };

  const renderBadges = () => {
    const badges = [];
    
    if (entity.badges.verified) {
      badges.push(
        <Chip
          key="verified"
          icon={<Verified />}
          label="Verifiziert"
          size="small"
          variant="outlined"
          sx={{
            borderColor: '#10b981',
            color: '#10b981',
            '& .MuiChip-icon': {
              color: '#10b981',
            }
          }}
        />
      );
    }
    
    if (entity.badges.certified) {
      badges.push(
        <Chip
          key="certified"
          icon={<WorkspacePremium />}
          label="Zertifiziert"
          size="small"
          variant="outlined"
          sx={{
            borderColor: '#6366f1',
            color: '#6366f1',
            '& .MuiChip-icon': {
              color: '#6366f1',
            }
          }}
        />
      );
    }
    
    if (entity.badges.recommended) {
      badges.push(
        <Chip
          key="recommended"
          icon={<ThumbUp />}
          label="Empfohlen"
          size="small"
          variant="outlined"
          sx={{
            borderColor: '#f59e0b',
            color: '#f59e0b',
            '& .MuiChip-icon': {
              color: '#f59e0b',
            }
          }}
        />
      );
    }
    
    return badges;
  };

  const renderMetaInfo = () => {
    const metaItems = [];
    
    if (entity.type === 'shop' && entity.listingsCount) {
      metaItems.push(`${entity.listingsCount} Anzeigen`);
    }
    
    if (entity.type === 'provider' && entity.experienceYears) {
      metaItems.push(`${entity.experienceYears} Jahre Erfahrung`);
    }
    
    if (entity.type === 'user' && entity.memberSince) {
      metaItems.push(`Mitglied seit ${entity.memberSince}`);
    }
    
    if (entity.priceFrom) {
      metaItems.push(`ab ${entity.priceFrom}`);
    }
    
    return metaItems.join(' • ');
  };

  const handleProfileClick = () => {
    // Alle Entitäten (User, Shop, Dienstleister) zu /user/{id} weiterleiten
    navigate(`/user/${entity.id}`);
  };

  const renderActionButtons = () => {
    const buttons = [];
    
    // Einheitlicher "Profil ansehen" Button für alle Entitäten
    buttons.push(
      <Button
        key="profile"
        variant="contained"
        size="small"
        startIcon={<Visibility />}
        onClick={handleProfileClick}
        sx={{
          backgroundColor: '#374151',
          color: 'white',
          fontSize: '0.75rem',
          textTransform: 'none',
          '&:hover': {
            backgroundColor: '#1f2937',
          }
        }}
      >
        Profil ansehen
      </Button>
    );
    
    if (onMessage) {
      buttons.push(
        <Button
          key="message"
          variant="outlined"
          size="small"
          startIcon={<Message />}
          onClick={() => onMessage(entity)}
          sx={{
            borderColor: '#d1d5db',
            color: '#374151',
            fontSize: '0.75rem',
            textTransform: 'none',
            '&:hover': {
              borderColor: '#9ca3af',
              backgroundColor: '#f9fafb',
            }
          }}
        >
          Nachricht
        </Button>
      );
    }
    
    return buttons;
  };

  const renderContactButtons = () => {
    const buttons = [];
    
    if (entity.contact?.phone && onCall) {
      buttons.push(
        <Tooltip key="phone" title="Anrufen">
          <IconButton
            size="small"
            onClick={() => onCall(entity)}
            sx={{
              color: '#6b7280',
              '&:hover': {
                color: '#374151',
                backgroundColor: '#f3f4f6',
              }
            }}
          >
            <Phone fontSize="small" />
          </IconButton>
        </Tooltip>
      );
    }
    
    if (entity.contact?.email && onEmail) {
      buttons.push(
        <Tooltip key="email" title="E-Mail senden">
          <IconButton
            size="small"
            onClick={() => onEmail(entity)}
            sx={{
              color: '#6b7280',
              '&:hover': {
                color: '#374151',
                backgroundColor: '#f3f4f6',
              }
            }}
          >
            <Email fontSize="small" />
          </IconButton>
        </Tooltip>
      );
    }
    
    if (entity.contact?.website && onWebsite) {
      buttons.push(
        <Tooltip key="website" title="Website besuchen">
          <IconButton
            size="small"
            onClick={() => onWebsite(entity)}
            sx={{
              color: '#6b7280',
              '&:hover': {
                color: '#374151',
                backgroundColor: '#f3f4f6',
              }
            }}
          >
            <Language fontSize="small" />
          </IconButton>
        </Tooltip>
      );
    }
    
    return buttons;
  };

  return (
    <Card
      sx={{
        height: 400, // Feste Höhe für alle Karten
        maxWidth: 300, // Maximale Breite begrenzen
        width: '100%',
        display: 'flex',
        flexDirection: 'column',
        transition: 'all 0.2s ease-in-out',
        borderRadius: 3,
        border: '1px solid #e5e7eb',
        backgroundColor: '#ffffff',
        '&:hover': {
          transform: 'translateY(-2px)',
          boxShadow: '0 4px 12px rgba(0,0,0,0.08)',
          borderColor: '#d1d5db',
        },
      }}
    >
      {/* Header mit Avatar und Typ */}
      <CardContent sx={{ pb: 1, flex: '0 0 auto' }}>
        <Box display="flex" alignItems="flex-start" gap={2} mb={2}>
          {entity.avatarUrl ? (
            <CardMedia
              component="img"
              sx={{
                width: 64,
                height: 64,
                borderRadius: 2,
                objectFit: 'cover',
                flexShrink: 0,
              }}
              image={entity.avatarUrl}
              alt={entity.name}
            />
          ) : (
            <Avatar
              sx={{
                width: 64,
                height: 64,
                bgcolor: getTypeColor(entity.type),
                fontSize: '1.4rem',
                fontWeight: 'bold',
                flexShrink: 0,
              }}
            >
              {entity.initials || getInitials(entity.name)}
            </Avatar>
          )}
          
          <Box flex={1} minWidth={0}>
            <Typography 
              variant="h6" 
              component="h3" 
              sx={{ 
                fontWeight: 600,
                fontSize: '1.1rem',
                lineHeight: 1.3,
                mb: 0.5,
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                display: '-webkit-box',
                WebkitLineClamp: 1,
                WebkitBoxOrient: 'vertical',
              }}
            >
              {entity.name}
            </Typography>
            {entity.subtitle && (
              <Typography 
                variant="body2" 
                color="text.secondary" 
                sx={{
                  fontSize: '0.85rem',
                  mb: 1,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  display: '-webkit-box',
                  WebkitLineClamp: 1,
                  WebkitBoxOrient: 'vertical',
                }}
              >
                {entity.subtitle}
              </Typography>
            )}
            <Chip
              label={getTypeLabel(entity.type)}
              size="small"
              variant="outlined"
              sx={{
                borderColor: '#d1d5db',
                color: '#6b7280',
                fontSize: '0.7rem',
                height: 22,
                fontWeight: 500,
                backgroundColor: '#f9fafb',
              }}
            />
          </Box>
        </Box>

        {/* Badges */}
        {renderBadges().length > 0 && (
          <Box display="flex" gap={0.5} mb={1.5} flexWrap="wrap">
            {renderBadges()}
          </Box>
        )}

        {/* Meta-Informationen */}
        {renderMetaInfo() && (
          <Typography 
            variant="body2" 
            color="text.secondary" 
            sx={{ 
              fontSize: '0.8rem',
              mb: 1,
              fontWeight: 500,
            }}
          >
            {renderMetaInfo()}
          </Typography>
        )}

        {/* Standort */}
        {entity.location && (
          <Box display="flex" alignItems="center" gap={0.5} mb={1}>
            <LocationOn fontSize="small" color="action" />
            <Typography 
              variant="body2" 
              color="text.secondary"
              sx={{ fontSize: '0.8rem' }}
            >
              {entity.location}
            </Typography>
          </Box>
        )}

        {/* Bewertung */}
        {entity.rating && (
          <Box display="flex" alignItems="center" gap={1} mb={1.5}>
            <Rating
              value={entity.rating.value}
              readOnly
              size="small"
              precision={0.1}
            />
            <Typography variant="body2" color="text.secondary" sx={{ fontSize: '0.8rem' }}>
              ({entity.rating.count})
            </Typography>
          </Box>
        )}
      </CardContent>

      {/* Beschreibung - Flexibler Bereich */}
      <CardContent sx={{ flex: '1 1 auto', py: 1 }}>
        {entity.description && (
          <Typography
            variant="body2"
            color="text.secondary"
            sx={{
              fontSize: '0.85rem',
              lineHeight: 1.4,
              display: '-webkit-box',
              WebkitLineClamp: 2,
              WebkitBoxOrient: 'vertical',
              overflow: 'hidden',
              mb: 1.5,
            }}
          >
            {entity.description.length > 100 
              ? entity.description.substring(0, 100) + '...' 
              : entity.description}
          </Typography>
        )}

        {/* Tags */}
        {entity.tags && entity.tags.length > 0 && (
          <Box display="flex" gap={0.5} flexWrap="wrap">
            {entity.tags.slice(0, 3).map((tag, index) => (
              <Chip
                key={index}
                label={tag}
                size="small"
                variant="outlined"
                sx={{ 
                  fontSize: '0.7rem', 
                  height: 20,
                  borderColor: '#e5e7eb',
                  color: '#6b7280',
                  backgroundColor: '#f9fafb',
                }}
              />
            ))}
            {entity.tags.length > 3 && (
              <Chip
                label={`+${entity.tags.length - 3}`}
                size="small"
                variant="outlined"
                sx={{ 
                  fontSize: '0.7rem', 
                  height: 20,
                  borderColor: '#e5e7eb',
                  color: '#6b7280',
                  backgroundColor: '#f9fafb',
                }}
              />
            )}
          </Box>
        )}
      </CardContent>

      <Divider />

      {/* Footer mit Aktionen - Feste Höhe */}
      <CardContent sx={{ pt: 1.5, pb: 1.5, flex: '0 0 auto' }}>
        <Box display="flex" justifyContent="space-between" alignItems="center">
          <Box display="flex" gap={1}>
            {renderActionButtons()}
          </Box>
          
          <Box display="flex" gap={0.5}>
            {renderContactButtons()}
          </Box>
        </Box>
      </CardContent>
    </Card>
  );
};

export default EntityCard;

import React, { useState, useEffect } from 'react';
import { Button, CircularProgress, Snackbar, Alert } from '@mui/material';
import { PersonAdd, PersonRemove, Check } from '@mui/icons-material';
import { useUser } from '../context/UserContext';

interface FollowButtonProps {
  userId: number;
  isFollowing?: boolean;
  onFollowChange?: (isFollowing: boolean) => void;
  size?: 'small' | 'medium' | 'large';
  variant?: 'contained' | 'outlined' | 'text';
  showIcon?: boolean;
}

const FollowButton: React.FC<FollowButtonProps> = ({
  userId,
  isFollowing: initialIsFollowing = false,
  onFollowChange,
  size = 'medium',
  variant = 'contained',
  showIcon = true
}) => {
  const [isFollowing, setIsFollowing] = useState(initialIsFollowing);
  const [isLoading, setIsLoading] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');
  const { user } = useUser();

  // Update local state when prop changes
  useEffect(() => {
    setIsFollowing(initialIsFollowing);
  }, [initialIsFollowing]);

  // Load follow status from backend (always check to ensure accuracy)
  useEffect(() => {
    const loadFollowStatus = async () => {
      if (!user || !userId || userId === user.id) return;
      
      try {
        const token = localStorage.getItem('token');
        if (!token) return;
        
        console.log('FollowButton - Loading follow status for user:', userId);
        
        const response = await fetch(`http://localhost:8000/api/users/${userId}/profile`, {
          headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
          }
        });
        
        if (response.ok) {
          const userData = await response.json();
          const isFollowing = userData.user?.is_following;
          if (isFollowing !== undefined && isFollowing !== null) {
            setIsFollowing(Boolean(isFollowing));
            console.log('FollowButton - Loaded follow status from backend:', isFollowing);
          }
        } else {
          console.error('FollowButton - Failed to load follow status:', response.status);
        }
      } catch (error) {
        console.error('Error loading follow status in FollowButton:', error);
      }
    };
    
    loadFollowStatus();
  }, [user, userId]);



  const handleFollowToggle = async () => {
    if (!user) {
      console.error('User not logged in');
      setSuccessMessage('Bitte logge dich ein');
      setShowSuccess(true);
      return;
    }

    if (userId === user.id) {
      console.error('Cannot follow yourself');
      return;
    }

    setIsLoading(true);

    try {
      const token = localStorage.getItem('token');
      
      if (!token) {
        console.error('No token found in localStorage');
        setSuccessMessage('Bitte logge dich erneut ein');
        setShowSuccess(true);
        return;
      }

      console.log('Using token:', token.substring(0, 20) + '...');
      
      const headers = {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      };

      if (isFollowing) {
        // Unfollow
        console.log('Unfollowing user:', userId);
        const response = await fetch(`http://localhost:8000/api/users/${userId}/follow`, {
          method: 'DELETE',
          headers
        });

        console.log('Unfollow response status:', response.status);

        if (response.ok) {
          setIsFollowing(false);
          setSuccessMessage('Erfolgreich entfolgt');
          setShowSuccess(true);
          onFollowChange?.(false);
        } else {
          const error = await response.json();
          console.error('Unfollow error:', error);
          setSuccessMessage(`Fehler: ${error.detail || 'Unbekannter Fehler'}`);
          setShowSuccess(true);
        }
      } else {
        // Follow
        console.log('Following user:', userId);
        const response = await fetch(`http://localhost:8000/api/users/${userId}/follow`, {
          method: 'POST',
          headers
        });

        console.log('Follow response status:', response.status);

        if (response.ok) {
          setIsFollowing(true);
          setSuccessMessage('Erfolgreich gefolgt');
          setShowSuccess(true);
          onFollowChange?.(true);
        } else {
          const error = await response.json();
          console.error('Follow error:', error);
          
          // Spezielle Behandlung für "bereits gefolgt" Fehler
          if (error.detail === "Du folgst diesem Account bereits") {
            setIsFollowing(true);
            setSuccessMessage('Du folgst diesem Account bereits');
            setShowSuccess(true);
            onFollowChange?.(true);
          } else {
            setSuccessMessage(`Fehler: ${error.detail || 'Unbekannter Fehler'}`);
            setShowSuccess(true);
          }
        }
      }
    } catch (error) {
      console.error('Follow/Unfollow error:', error);
      setSuccessMessage('Netzwerkfehler - bitte versuche es erneut');
      setShowSuccess(true);
    } finally {
      setIsLoading(false);
    }
  };

  // Debug: Log user and token info
  useEffect(() => {
    console.log('FollowButton - User:', user);
    console.log('FollowButton - Token in localStorage:', localStorage.getItem('token') ? 'Present' : 'Missing');
    console.log('FollowButton - UserId to follow:', userId);
    console.log('FollowButton - initialIsFollowing:', initialIsFollowing);
    console.log('FollowButton - isFollowing state:', isFollowing);
  }, [user, userId, initialIsFollowing, isFollowing]);

  // Don't show button if user is not logged in or trying to follow themselves
  if (!user || userId === user.id) {
    console.log('FollowButton - Not showing button. User:', user, 'UserId:', userId);
    return null;
  }

  const getButtonText = () => {
    if (isLoading) return '';
    return isFollowing ? 'Entfolgen' : 'Folgen';
  };

  const getButtonIcon = () => {
    if (isLoading) return <CircularProgress size={16} />;
    if (isFollowing) return <PersonRemove />;
    return <PersonAdd />;
  };

  const getButtonColor = () => {
    if (isFollowing) return 'secondary';
    return 'primary';
  };

  return (
    <>
      <Button
        variant={isFollowing ? 'outlined' : variant}
        color={getButtonColor()}
        size={size}
        onClick={handleFollowToggle}
        disabled={isLoading}
        startIcon={showIcon ? getButtonIcon() : undefined}
        sx={{
          minWidth: 100,
          textTransform: 'none',
          fontWeight: 500,
          borderRadius: 2,
          ...(isFollowing && {
            borderColor: 'primary.main',
            color: 'primary.main',
            '&:hover': {
              borderColor: 'primary.dark',
              backgroundColor: 'primary.light',
              color: 'primary.dark'
            }
          })
        }}
      >
        {getButtonText()}
      </Button>

      <Snackbar
        open={showSuccess}
        autoHideDuration={3000}
        onClose={() => setShowSuccess(false)}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert 
          onClose={() => setShowSuccess(false)} 
          severity="success" 
          variant="filled"
          icon={<Check />}
        >
          {successMessage}
        </Alert>
      </Snackbar>
    </>
  );
};

