// Helper function for image URLs
const getImageUrl = (imagePath: string) => {
  if (!imagePath) return '';
  if (imagePath.startsWith('http')) return imagePath;

  // Entferne /api/uploads/ falls bereits vorhanden
  let cleanPath = imagePath;
  if (cleanPath.startsWith('/api/uploads/')) {
    cleanPath = cleanPath.replace('/api/uploads/', '');
  }
  if (cleanPath.startsWith('api/uploads/')) {
    cleanPath = cleanPath.replace('api/uploads/', '');
  }

  return `http://localhost:8000/api/uploads/${cleanPath}`;
};

// Mobile Image Gallery Component
const MobileImageGallery = ({ 
  images, 
  selectedIndex, 
  onImageChange, 
  onImageClick 
}: { 
  images: string[]; 
  selectedIndex: number; 
  onImageChange: (index: number) => void; 
  onImageClick: (index: number) => void; 
}) => {
  const [touchStart, setTouchStart] = useState<number | null>(null);
  const [touchEnd, setTouchEnd] = useState<number | null>(null);
  const [currentIndex, setCurrentIndex] = useState(selectedIndex);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const galleryRef = useRef(null);

  // Minimum swipe distance (in px)
  const minSwipeDistance = 50;

  useEffect(() => {
    setCurrentIndex(selectedIndex);
  }, [selectedIndex]);

  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(null);
    setTouchStart(e.targetTouches[0].clientX);
  };

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd(e.targetTouches[0].clientX);
  };

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return;

    const distance = touchStart - touchEnd;
    const isLeftSwipe = distance > minSwipeDistance;
    const isRightSwipe = distance < -minSwipeDistance;

    if (isLeftSwipe && currentIndex < images.length - 1) {
      handleImageChange(currentIndex + 1);
    } else if (isRightSwipe && currentIndex > 0) {
      handleImageChange(currentIndex - 1);
    }
  };

  const handleImageChange = (newIndex: number) => {
    if (isTransitioning || newIndex < 0 || newIndex >= images.length) return;

    setIsTransitioning(true);
    setCurrentIndex(newIndex);
    onImageChange(newIndex);

    // Reset transition state after animation
    setTimeout(() => setIsTransitioning(false), 300);
  };

  const goToPrevious = () => {
    if (currentIndex > 0) {
      handleImageChange(currentIndex - 1);
    }
  };

  const goToNext = () => {
    if (currentIndex < images.length - 1) {
      handleImageChange(currentIndex + 1);
    }
  };

  return (
    <Box
      ref={galleryRef}
      sx={{
        position: 'relative',
        width: '85%', // Bildfenster kleiner machen - optimal!
        height: { xs: 280, sm: 350, md: 400 },
        overflow: 'hidden',
        borderRadius: { xs: '8px', sm: '12px' },
        bgcolor: '#f5f5f5',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        marginLeft: '0', // Links ausrichten
        marginRight: 'auto' // Rechts automatisch
      }}
      onTouchStart={onTouchStart}
      onTouchMove={onTouchMove}
      onTouchEnd={onTouchEnd}
    >
      {/* Main Image */}
      <Box
        component="img"
        src={getImageUrl(images[currentIndex])}
        alt={`Image ${currentIndex + 1}`}
        onClick={() => onImageClick(currentIndex)}
        sx={{
          width: '100%',
          height: '100%',
          objectFit: 'contain',
          cursor: 'pointer',
          transition: 'opacity 0.3s ease',
          opacity: isTransitioning ? 0.8 : 1,
          objectPosition: 'center center' // Bild perfekt zentrieren
        }}
      />

      {/* Image Counter */}
      <Box
        sx={{
          position: 'absolute',
          top: 12,
          right: 12,
          bgcolor: 'rgba(0,0,0,0.7)',
          color: 'white',
          px: 1.5,
          py: 0.5,
          borderRadius: '12px',
          fontSize: { xs: '0.75rem', sm: '0.875rem' },
          fontWeight: 500,
          zIndex: 5
        }}
      >
        {currentIndex + 1} / {images.length}
      </Box>

      {/* Navigation Arrows */}
      {images.length > 1 && (
        <>
          <IconButton
            onClick={goToPrevious}
            disabled={currentIndex === 0}
            sx={{
              position: 'absolute',
              left: { xs: 8, sm: 12 },
              top: '50%',
              transform: 'translateY(-50%)',
              color: 'white',
              bgcolor: 'rgba(0,0,0,0.6)',
              zIndex: 10,
              width: { xs: 36, sm: 44 },
              height: { xs: 36, sm: 44 },
              opacity: currentIndex === 0 ? 0.3 : 1,
              '&:hover': { 
                bgcolor: 'rgba(0,0,0,0.8)',
                transform: 'translateY(-50%) scale(1.1)'
              },
              transition: 'all 0.2s ease',
              '& .MuiSvgIcon-root': {
                fontSize: { xs: 20, sm: 24 }
              }
            }}
          >
            <NavigateBeforeIcon />
          </IconButton>

          <IconButton
            onClick={goToNext}
            disabled={currentIndex === images.length - 1}
            sx={{
              position: 'absolute',
              right: { xs: 8, sm: 12 },
              top: '50%',
              transform: 'translateY(-50%)',
              color: 'white',
              bgcolor: 'rgba(0,0,0,0.6)',
              zIndex: 10,
              width: { xs: 36, sm: 44 },
              height: { xs: 36, sm: 44 },
              opacity: currentIndex === images.length - 1 ? 0.3 : 1,
              '&:hover': { 
                bgcolor: 'rgba(0,0,0,0.8)',
                transform: 'translateY(-50%) scale(1.1)'
              },
              transition: 'all 0.2s ease',
              '& .MuiSvgIcon-root': {
                fontSize: { xs: 20, sm: 24 }
              }
            }}
          >
            <NavigateNextIcon />
          </IconButton>
        </>
      )}

      {/* Thumbnail Strip */}
      {images.length > 1 && (
        <Box
          sx={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            right: 0,
            bgcolor: 'rgba(0,0,0,0.7)',
            py: 1,
            px: 1,
            display: 'flex',
            gap: 0.5,
            justifyContent: 'center',
            overflow: 'auto',
            '&::-webkit-scrollbar': {
              height: 3
            },
            '&::-webkit-scrollbar-track': {
              background: 'transparent'
            },
            '&::-webkit-scrollbar-thumb': {
              background: 'rgba(255,255,255,0.3)',
              borderRadius: 2
            }
          }}
        >
          {images.map((image, index) => (
            <Box
              key={index}
              component="img"
              src={getImageUrl(image)}
              alt={`Thumbnail ${index + 1}`}
              onClick={() => handleImageChange(index)}
              sx={{
                width: { xs: 40, sm: 50 },
                height: { xs: 27, sm: 33 },
                minWidth: { xs: 40, sm: 50 },
                objectFit: 'cover',
                borderRadius: '4px',
                cursor: 'pointer',
                border: index === currentIndex ? '2px solid #1976d2' : '1px solid rgba(255,255,255,0.3)',
                transition: 'all 0.2s ease',
                opacity: index === currentIndex ? 1 : 0.7,
                '&:hover': { 
                  opacity: 1,
                  transform: 'scale(1.05)'
                }
              }}
            />
          ))}
        </Box>
      )}
    </Box>
  );
};

