} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';

interface ListingPreviewProps {
  formData: Record<string, string | number | boolean>;
  images: File[];
  type: 'auto' | 'kleinanzeigen';
  onBack: () => void;
  onPublish: () => void;
