export const MobileBottomNavigation: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useUser();
  const { favorites } = useFavorites();

  const getCurrentValue = () => {
    const path = location.pathname;
    if (path === '/') return 0;
    if (path.startsWith('/category') || path.startsWith('/search')) return 1;
    if (path === '/favorites' || path.includes('dashboard?tab=favorites')) return 2;
    if (path === '/login') return 3;
    if (path === '/create-listing' || path === '/category-selection') return 4;
    return 0;
  };

  const handleChange = (event: React.SyntheticEvent, newValue: number) => {
    switch (newValue) {
      case 0:
        navigate('/kleinanzeigen');
        break;
      case 1:
        navigate('/category/elektronik');
        break;
      case 2:
        if (user) {
          navigate('/dashboard?tab=favorites');
        } else {
          navigate('/login');
        }
        break;
      case 3:
        navigate('/login');
        break;
      case 4:
        if (user) {
          navigate('/create-listing');
        } else {
          navigate('/login');
        }
        break;
    }
  };

  return (
    <Paper
      sx={{
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 1000,
        display: { xs: 'block', md: 'none' }, // Nur auf mobilen Geräten anzeigen
        borderTop: '1px solid #e0e0e0',
        backgroundColor: 'white'
      }}
      elevation={3}
    >
      <BottomNavigation
        value={getCurrentValue()}
        onChange={handleChange}
        sx={{
          height: 64, // Größere Höhe für bessere Touch-Targets
          '& .MuiBottomNavigationAction-root': {
            minWidth: 'auto',
            padding: '6px 12px 8px',
            '&.Mui-selected': {
              color: '#e31b23'
            }
          },
          '& .MuiBottomNavigationAction-label': {
            fontSize: '0.7rem',
            fontWeight: 500,
            marginTop: '2px'
          }
        }}
      >
        <BottomNavigationAction
          label="Start"
          icon={<HomeIcon />}
          sx={{
            '&.Mui-selected': {
              '& .MuiSvgIcon-root': {
                color: '#e31b23'
              }
            }
          }}
        />
        <BottomNavigationAction
          label="Suche"
          icon={<SearchIcon />}
          sx={{
            '&.Mui-selected': {
              '& .MuiSvgIcon-root': {
                color: '#e31b23'
              }
            }
          }}
        />
        <BottomNavigationAction
          label="Favoriten"
          icon={
            <Badge
              badgeContent={favorites.size > 0 ? favorites.size : 0}
              color="error"
              sx={{
                '& .MuiBadge-badge': {
                  fontSize: '0.6rem',
                  minWidth: '16px',
                  height: '16px',
                  borderRadius: '8px'
                }
              }}
            >
              <FavoriteIcon />
            </Badge>
          }
          sx={{
            '&.Mui-selected': {
              '& .MuiSvgIcon-root': {
                color: '#e31b23'
              }
            }
          }}
        />
        <BottomNavigationAction
          label="Dashboard"
          icon={<PersonIcon />}
          sx={{
            '&.Mui-selected': {
              '& .MuiSvgIcon-root': {
