    case 'kleinanzeigen':
      return '📱';
    default:
      return '📦';
  }
};

const getSubcategoryIcon = (categorySlug: string, subcategorySlug: string) => {
  if (categorySlug === 'autos') {
    switch (subcategorySlug) {
      case 'autos':
        return '🚗';
      case 'motorraeder':
        return '🏍️';
      case 'wohnmobil':
        return '🚐';
      case 'lkw':
        return '🚛';
      case 'ersatzteile':
        return '🔧';
      default:
        return '🚗';
    }
  } else if (categorySlug === 'kleinanzeigen') {
    switch (subcategorySlug) {
      case 'elektronik':
