      user: { id: 1, email: 'admin@example.com', role: 'admin' },
      isLoading: false,
      setUser: jest.fn(),
      fetchUser: jest.fn(),
      logout: jest.fn(),
      refreshUser: jest.fn(),
    } as any);

    const ComplexComponent = () => (
      <div>
        <h1>Admin Dashboard</h1>
        <p>Welcome to admin panel</p>
        <button>Manage Users</button>
        <button>System Settings</button>
      </div>
    );

    render(
      <MemoryRouter>
        <AdminRoute>
          <ComplexComponent />
        </AdminRoute>
      </MemoryRouter>
    );

    expect(screen.getByText('Admin Dashboard')).toBeInTheDocument();
    expect(screen.getByText('Welcome to admin panel')).toBeInTheDocument();
    expect(screen.getByText('Manage Users')).toBeInTheDocument();
    expect(screen.getByText('System Settings')).toBeInTheDocument();
  });

  it('handles loading state with proper styling', () => {
    mockUseUser.mockReturnValue({
      user: null,
      isLoading: true,
      setUser: jest.fn(),
      fetchUser: jest.fn(),
      logout: jest.fn(),
      refreshUser: jest.fn(),
    } as any);

    render(
      <MemoryRouter>
        <AdminRoute>
          <TestComponent />
        </AdminRoute>
      </MemoryRouter>
    );

    const loadingBox = screen.getByRole('progressbar').closest('.MuiBox-root');
    expect(loadingBox).toBeInTheDocument();
  });

  it('shows error alert with proper styling for non-admin users', () => {
    mockUseUser.mockReturnValue({
      user: { id: 2, email: 'user@example.com', role: 'user' },
      isLoading: false,
      setUser: jest.fn(),
