  // Funktion zum Abrufen der verfügbaren Modelle basierend auf der Marke
  const getAvailableModels = (brand: string) => {
    const brandKey = brand.toLowerCase() as keyof typeof modelDatabase;
    return modelDatabase[brandKey] || [];
  };

  // Handler für Marken-Änderung - setzt Modell zurück
  const handleBrandChange = (newBrand: string) => {
    setBrandValue(newBrand);
    // Setze Modell zurück, wenn sich die Marke ändert
    if (modelValue && !getAvailableModels(newBrand).includes(modelValue)) {
      setModelValue('');
    }
  };

  // Lade echte Daten aus der API
  const fetchAutos = async (appliedFilters: any = {}) => {
    console.log('=== fetchAutos called ===');
    try {
      setLoading(true);
      setError(null);

      // Baue Query-Parameter mit verbesserter Filterlogik
      const queryParams = new URLSearchParams({
        category: 'autos',
        ...appliedFilters
      });

      // Entferne leere Werte
      for (const [key, value] of queryParams.entries()) {
        if (value === '' || value === null || value === undefined) {
          queryParams.delete(key);
        }
      }

      // Log für Debugging
      console.log('Sending filters to backend:', Object.fromEntries(queryParams));

      const response = await fetch(`http://localhost:8000/api/listings?${queryParams.toString()}`);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();

      // Backend gibt jetzt ein Objekt mit listings zurück
      const listings = Array.isArray(data) ? data : (data.listings || []);

      console.log('Received from backend:', data);
      console.log('Total listings:', listings.length);

      // Verwende die gefilterten Anzeigen direkt
      const autosData = listings.map((listing: any) => {
        // Debug: Log die ursprünglichen Bilder
        console.log(`Listing ${listing.id} - Original images:`, listing.images);

        // Robuste Bildverarbeitung für alle Bilder
        let imageUrl = ''; // This variable still holds only the first image URL
        let parsedImages: string[] = []; // New variable to hold all parsed images
        try {
          if (listing.images) {
            let images;
            // Prüfe ob images bereits ein Array ist oder ein JSON-String
            if (Array.isArray(listing.images)) {
              images = listing.images;
            } else if (typeof listing.images === 'string' && listing.images.trim() !== '') {
              images = JSON.parse(listing.images);
            } else {
              images = [];
            }

            console.log(`Listing ${listing.id} - Parsed images:`, images);

            if (Array.isArray(images) && images.length > 0) {
              parsedImages = images.map((imagePath: string) => { // Map all images to full URLs
                if (imagePath.startsWith('/uploads/')) {
                  return imagePath; // Behalte den relativen Pfad bei
                }
                return imagePath;
              });
              imageUrl = parsedImages[0] || ''; // Still taking only the first for `imageUrl`
            } else {
              // Fallback zu Placeholder wenn keine Bilder vorhanden
              parsedImages = [PLACEHOLDER_IMAGE_URL];
              imageUrl = PLACEHOLDER_IMAGE_URL;
            }
          }
        } catch (error) {
          console.warn('Fehler beim Parsen der Bilder für Listing:', listing.id, error);
        }

        // Parse attributes sicher
        let attributes: any = {};
        try {
          if (listing.attributes) {
            if (typeof listing.attributes === 'string') {
              attributes = JSON.parse(listing.attributes);
            } else {
              attributes = listing.attributes;
            }
          }
        } catch (error) {
          console.warn('Fehler beim Parsen der attributes für Listing:', listing.id, error);
          attributes = {};
        }

        // Debug: Log die finalen Bilder
        console.log(`Listing ${listing.id} - Final parsedImages for AdCard:`, parsedImages);

        // Debug: Log die attributes
        console.log(`Listing ${listing.id} - Raw attributes:`, attributes);
        console.log(`Listing ${listing.id} - kilometerstand:`, attributes.kilometerstand);
        console.log(`Listing ${listing.id} - erstzulassung:`, attributes.erstzulassung);
        console.log(`Listing ${listing.id} - kraftstoff:`, attributes.kraftstoff);
        console.log(`Listing ${listing.id} - getriebe:`, attributes.getriebe);

        // Erstelle detaillierte Fahrzeuginformationen für die Anzeige
