          marke: attributes.brand || attributes.marke || '',
          modell: attributes.model || attributes.modell || '',
          erstzulassung: attributes.year || attributes.erstzulassung || '',
          kilometerstand: attributes.mileage || attributes.kilometerstand || '',
          kraftstoff: attributes.fuel || attributes.kraftstoff || '',
          getriebe: attributes.transmission || attributes.getriebe || '',
          leistung: attributes.power || attributes.leistung || '',
          farbe: attributes.color || attributes.farbe || '',
          unfallfrei: attributes.accident_free !== undefined ? attributes.accident_free : (attributes.unfallfrei || false)
        };

        // Debug: Log die finalen vehicleDetails
        console.log(`Listing ${listing.id} - Final vehicleDetails:`, vehicleDetails);

        // Check if this listing has any meaningful vehicle data
        const hasVehicleData = vehicleDetails.kilometerstand || vehicleDetails.erstzulassung || vehicleDetails.kraftstoff || vehicleDetails.getriebe;
