          console.log(`Listing ${listing.id} - HAS vehicle data:`, hasVehicleData);
        } else {
          console.log(`Listing ${listing.id} - NO vehicle data`);
        }

        // Intelligenter Titel: Wenn der ursprüngliche Titel generisch ist (pkw, auto, etc.), 
        // verwende Marke und Modell als Titel
        let displayTitle = listing.title;
        const genericTitles = ['pkw', 'auto', 'fahrzeug', 'car', 'vehicle'];
        const isGenericTitle = genericTitles.some(generic => 
          listing.title.toLowerCase().includes(generic.toLowerCase())
        );

        if (isGenericTitle && attributes.marke && attributes.modell) {
          displayTitle = `${attributes.marke} ${attributes.modell}`;
        } else if (isGenericTitle && attributes.marke) {
          displayTitle = attributes.marke;
        }

