            lg: 'repeat(4, 1fr)', // Large: 4 Spalten
            xl: 'repeat(5, 1fr)'  // Extra Large: 5 Spalten
          },
          gap: { xs: 1.5, sm: 1.5, md: 2, lg: 2.5 },
          mt: 2,
          alignItems: 'start' // Verhindert, dass Karten sich aneinander anpassen
        }}>
          {autos.map((auto) => {
            return (
            <Box key={auto.id}>
              <AdCard
                id={auto.id.toString()}
                title={auto.title}
                price={auto.price}
                location={auto.location}
                images={auto.images} // This is correctly passing the array
                category="autos"
                status="active"
                seller={{
                  name: 'Anbieter',
                  rating: auto.rating,
                  reviewCount: auto.reviews
                }}
                vehicleDetails={auto.vehicleDetails}
              />
            </Box>
          )})}
        </Box>
      )}
    </Container>
  );
};

