                        }}
                      />
                      {subcategory.items && (
                        <NavigateNextIcon fontSize="small" sx={{ color: '#666' }} />
                      )}
                    </ListItemButton>
                  </ListItem>
                ))}
              </List>
            </>
          ) : (
            <Box sx={{ p: 4, textAlign: 'center', color: '#999' }}>
              <Typography variant="body2">
