        </Grid>

        {/* Rechte Spalte - Spezifische Items */}
        <Grid item xs={12} md={4}>
          {selectedSubcategory && selectedSubcategory.items ? (
            <>
              <Box sx={{ p: 2, bgcolor: '#f5f5f5', borderBottom: '1px solid #e0e0e0' }}>
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <ArrowBackIcon 
                    sx={{ mr: 1, cursor: 'pointer', color: '#666' }} 
                    onClick={handleBack}
                  />
                  <Typography variant="h6" sx={{ fontWeight: 600, color: '#333' }}>
                    Art *
                  </Typography>
                </Box>
              </Box>
              <List sx={{ p: 0 }}>
                {selectedSubcategory.items.map((item, index) => (
                  <ListItem key={index} disablePadding>
                    <ListItemButton 
                      onClick={() => handleItemSelect(item)}
                      sx={{
                        py: 1.5,
                        px: 2,
                        borderBottom: '1px solid #f0f0f0',
                        '&:hover': {
                          bgcolor: '#f8f9fa'
                        }
                      }}
                    >
                      <ListItemText 
                        primary={item}
                        primaryTypographyProps={{
                          fontSize: '0.9rem'
                        }}
                      />
                    </ListItemButton>
                  </ListItem>
                ))}
              </List>
            </>
          ) : (
            <Box sx={{ p: 4, textAlign: 'center', color: '#999' }}>
              <Typography variant="body2">
                {selectedCategory ? 'Wählen Sie eine Unterkategorie aus' : 'Wählen Sie zuerst eine Kategorie aus'}
              </Typography>
            </Box>
          )}
        </Grid>
      </Grid>

      {/* Weiter Button */}
      {selectedSubcategory && (
        <Box sx={{ mt: 3, display: 'flex', justifyContent: 'flex-end' }}>
          <Box
            component="button"
            onClick={() => {
              // Navigiere zur CreateListing-Seite mit der ausgewählten Unterkategorie
              navigate('/create-listing', { 
                state: { 
                  category: selectedCategory?.value,
                  subcategory: selectedSubcategory?.value
                }
              });
            }}
            sx={{
              bgcolor: '#2e7d32',
              color: 'white',
              border: 'none',
              borderRadius: 1,
              px: 4,
              py: 1.5,
              fontSize: '1rem',
              fontWeight: 600,
              cursor: 'pointer',
              '&:hover': {
                bgcolor: '#1b5e20'
              }
            }}
          >
            Weiter
          </Box>
        </Box>
      )}

      {/* Ausgewählte Kategorie anzeigen */}
      {selectedCategory && (
        <Box sx={{ mt: 4 }}>
          <Divider sx={{ mb: 2 }} />
          <Typography variant="h6" gutterBottom>
            Ausgewählte Kategorie:
          </Typography>
          <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
            <Chip 
              label={selectedCategory.label} 
              icon={<span>{selectedCategory.icon}</span>}
              color="primary"
              variant="outlined"
            />
            {selectedSubcategory && (
              <Chip 
                label={selectedSubcategory.label} 
                color="secondary"
                variant="outlined"
              />
            )}
          </Box>
        </Box>
      )}
    </Container>
  );

  return (
    <>
      {isMobile ? (
        <Drawer
          anchor="bottom"
          open={true}
          onClose={handleClose}
          sx={{
            '& .MuiDrawer-paper': {
              height: '90vh',
              borderTopLeftRadius: 16,
              borderTopRightRadius: 16,
            },
          }}
        >
          <MobileModalContent />
        </Drawer>
      ) : (
        <DesktopLayout />
      )}
    </>
  );
};

