interface Conversation {
  id: string;
  title: string;
  lastMessage: string;
  timestamp: string;
  unreadCount: number;
  avatar: string;
  isOnline: boolean;
  sellerId: number;
  listingId: number;
  listingTitle: string;
  listingPrice: number;
  listingImage: string;
}

interface Message {
  id: string;
  content: string;
  senderId: number;
  timestamp: string;
  isRead: boolean;
  isOwn: boolean;
  type: 'text' | 'image' | 'file';
}

export const ChatPage: React.FC = () => {
  // State Management
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' as 'success' | 'error' });

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Hooks
  const { user } = useUser();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Effects
  useEffect(() => {
    if (user) {
      loadConversations();
    }
  }, [user]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    if (selectedConversation) {
      loadMessages(selectedConversation.id);
    }
  }, [selectedConversation]);

  useEffect(() => {
    const listingId = searchParams.get('listingId');
    const sellerId = searchParams.get('sellerId');

    if (listingId && sellerId && conversations.length > 0) {
      // Erstelle oder finde Konversation basierend auf URL-Parametern
      handleConversationFromURL(listingId, sellerId);
    }
  }, [searchParams, conversations]);

  // Functions
  const loadConversations = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('token');
      if (!token) return;

      const response = await fetch('http://localhost:8000/api/conversations', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const data = await response.json();
        const conversations: Conversation[] = data.conversations.map((conv: any) => ({
          id: conv.id.toString(),
          title: conv.listing_title || 'Anzeige',
          lastMessage: conv.last_message?.content || '',
          timestamp: new Date(conv.last_message?.created_at || conv.updated_at).toLocaleTimeString('de-DE', { 
            hour: '2-digit', 
            minute: '2-digit' 
          }),
          unreadCount: conv.unread_count || 0,
          avatar: conv.other_user?.name?.charAt(0) || 'U',
          isOnline: Math.random() > 0.5, // Temporär - später echte Online-Status
          sellerId: conv.other_user?.id || 0,
          listingId: conv.listing_id || 0,
          listingTitle: conv.listing_title || '',
          listingPrice: conv.listing_price || 0,
          listingImage: conv.listing_image || ''
        }));
        setConversations(conversations);
      } else {
        console.error('Fehler beim Laden der Konversationen:', response.statusText);
        setConversations([]);
      }
    } catch (error) {
      console.error('Fehler beim Laden der Konversationen:', error);
      setConversations([]);
    } finally {
      setLoading(false);
    }
  };

  const loadMessages = async (conversationId: string) => {
    try {
      const token = localStorage.getItem('token');
      if (!token) return;

      const response = await fetch(`http://localhost:8000/api/conversations/${conversationId}/messages`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const data = await response.json();
        const messages: Message[] = data.messages.map((msg: any) => ({
          id: msg.id.toString(),
          content: msg.content,
          senderId: msg.sender_id,
          timestamp: msg.created_at,
          isRead: msg.is_read,
          isOwn: msg.sender_id === user?.id,
          type: 'text' as const
        }));
        setMessages(messages);
      } else {
        console.error('Fehler beim Laden der Nachrichten:', response.statusText);
        setMessages([]);
      }
        } catch (error) {
      console.error('Fehler beim Laden der Nachrichten:', error);
      setMessages([]);
    }
  };

  const handleConversationFromURL = async (listingId: string, sellerId: string) => {
    // Finde oder erstelle Konversation basierend auf URL-Parametern
    const existingConversation = conversations.find(c => 
      c.listingId.toString() === listingId && c.sellerId.toString() === sellerId
    );

    if (existingConversation) {
      setSelectedConversation(existingConversation);
    } else {
      // Erstelle neue Konversation über ChatService
      try {
        const conversationId = await chatService.createConversation(
          parseInt(listingId),
          parseInt(sellerId)
        );

        // Lade Conversations neu, um die neue Conversation zu bekommen
        await loadConversations();

        // Finde die neue Conversation
        const newConversation = conversations.find(c => 
          c.id === conversationId.toString()
        );

        if (newConversation) {
          setSelectedConversation(newConversation);
        }
      } catch (error) {
        console.error('Fehler beim Erstellen der Konversation:', error);
      }
    }
  };

  const handleSendMessage = async () => {
    if (!newMessage.trim() || !user || !selectedConversation) return;

    const token = localStorage.getItem('token');
    if (!token) return;

    try {
      const response = await fetch(`http://localhost:8000/api/conversations/${selectedConversation.id}/messages`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ content: newMessage.trim() })
      });

      if (response.ok) {
        const data = await response.json();
        const message: Message = {
          id: data.id.toString(),
          content: data.content,
          senderId: data.sender_id,
          timestamp: data.created_at,
          isRead: data.is_read,
          isOwn: true,
          type: 'text'
        };

        setMessages(prev => [...prev, message]);
        setNewMessage('');

        // Lade Konversationen neu um letzte Nachricht zu aktualisieren
        loadConversations();
      } else {
        console.error('Fehler beim Senden der Nachricht:', response.statusText);
        setSnackbar({ open: true, message: 'Fehler beim Senden der Nachricht', severity: 'error' });
      }
    } catch (error) {
      console.error('Fehler beim Senden der Nachricht:', error);
      setSnackbar({ open: true, message: 'Fehler beim Senden der Nachricht', severity: 'error' });
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleFileUpload = () => {
    fileInputRef.current?.click();
  };

  const handleMenuClick = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const formatTime = (timestamp: string) => {
    return new Date(timestamp).toLocaleTimeString('de-DE', {
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const filteredConversations = conversations.filter(conv =>
    conv.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    conv.lastMessage.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (!user) {
    return (
      <DashboardLayout>
        <Container maxWidth="md" sx={{ py: 4 }}>
          <Fade in timeout={800}>
        <Paper
              elevation={0}
          sx={{
                p: 6, 
            textAlign: 'center',
            borderRadius: 3,
                background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)',
                border: '1px solid #e2e8f0'
              }}
            >
              <Zoom in timeout={1000}>
                <Box sx={{ mb: 4 }}>
                  <MessageIcon sx={{ fontSize: 80, color: 'primary.main', mb: 2 }} />
          </Box>
              </Zoom>
              <Typography variant="h4" gutterBottom fontWeight={600} color="text.primary">
            Chat-Funktion
          </Typography>
              <Typography variant="body1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
            Melde dich an, um mit Verkäufern zu chatten und Fragen zu stellen.
          </Typography>
            <Button
              variant="contained"
                onClick={() => navigate('/login')}
              size="large"
              sx={{ 
                  px: 4,
                  py: 1.5,
                borderRadius: 2,
                fontSize: '1.1rem',
                fontWeight: 600,
                  boxShadow: '0 4px 20px rgba(25, 118, 210, 0.3)',
                '&:hover': { 
                    boxShadow: '0 6px 25px rgba(25, 118, 210, 0.4)',
                }
              }}
            >
              Jetzt anmelden
            </Button>
        </Paper>
          </Fade>
        </Container>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <Box sx={{ height: 'calc(100vh - 120px)', display: 'flex', bgcolor: '#f8fafc' }}>
        {/* Conversations Sidebar */}
        <Paper 
          elevation={0}
          sx={{ 
            width: 380, 
            borderRight: '1px solid #e2e8f0',
           display: 'flex', 
            flexDirection: 'column',
            bgcolor: 'white'
          }}
        >
          {/* Sidebar Header */}
          <Box sx={{ p: 3, borderBottom: '1px solid #e2e8f0' }}>
            <Box display="flex" alignItems="center" justifyContent="space-between" mb={2}>
              <Typography variant="h5" fontWeight={700} color="text.primary">
                Nachrichten
              </Typography>
              <IconButton size="small" onClick={handleMenuClick}>
                <MoreVertIcon />
              </IconButton>
            </Box>

            {/* Search Bar */}
            <TextField
              fullWidth
              placeholder="Konversationen durchsuchen..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              size="small"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <SearchIcon sx={{ color: 'text.secondary' }} />
                  </InputAdornment>
                ),
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  borderRadius: 2,
           bgcolor: '#f8fafc',
                  '&:hover': {
                    bgcolor: '#f1f5f9'
