                }
              }}
            />
          </Box>

          {/* Conversations List */}
          <Box sx={{ flex: 1, overflow: 'auto' }}>
            {loading ? (
              <Box sx={{ p: 2 }}>
                {[1, 2, 3].map((i) => (
                  <Box key={i} sx={{ mb: 2 }}>
                    <Skeleton variant="rectangular" height={60} sx={{ borderRadius: 2 }} />
                  </Box>
                ))}
              </Box>
            ) : filteredConversations.length === 0 ? (
              <Box sx={{ p: 4, textAlign: 'center' }}>
                <MessageIcon sx={{ fontSize: 48, color: 'text.secondary', mb: 2 }} />
                <Typography variant="body2" color="text.secondary">
                  {searchQuery ? 'Keine Konversationen gefunden' : 'Noch keine Konversationen'}
                </Typography>
              </Box>
            ) : (
              <List sx={{ p: 0 }}>
                {filteredConversations.map((conversation, index) => (
                  <React.Fragment key={conversation.id}>
                    <ListItemButton
                      onClick={() => setSelectedConversation(conversation)}
                      selected={selectedConversation?.id === conversation.id}
                  sx={{ 
                        p: 2,
                        '&.Mui-selected': {
                          bgcolor: 'primary.50',
                          borderRight: '3px solid',
                          borderColor: 'primary.main'
                        },
                    '&:hover': { 
                          bgcolor: 'grey.50'
                        }
                      }}
                    >
                      <ListItemAvatar>
                        <Badge
                          overlap="circular"
                          anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
                          badgeContent={
                 <Box
                   sx={{
                                width: 12,
                                height: 12,
                                borderRadius: '50%',
                                bgcolor: conversation.isOnline ? '#10b981' : '#6b7280',
                                border: '2px solid white'
                              }}
                            />
                          }
                        >
                          <Avatar sx={{ bgcolor: 'primary.main', fontWeight: 600 }}>
                            {conversation.avatar}
                          </Avatar>
                        </Badge>
                      </ListItemAvatar>
                      <Box sx={{ flex: 1, minWidth: 0 }}>
                        <Box display="flex" alignItems="center" justifyContent="space-between">
                          <Box>
                   <Typography 
                     variant="subtitle1" 
                              fontWeight={600} 
                              noWrap
                     sx={{ 
                                cursor: 'pointer',
                                '&:hover': { color: 'primary.main' }
                              }}
                              onClick={(e) => {
                                e.stopPropagation();
                                navigate(`/listing/${conversation.listingId}`);
                              }}
                            >
                              {conversation.title}
                            </Typography>
                            <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.75rem' }}>
                              mit {conversation.avatar} • {conversation.listingPrice > 0 && `${conversation.listingPrice}€`}
                            </Typography>
                          </Box>
                          <Typography variant="caption" color="text.secondary">
                            {conversation.timestamp}
                   </Typography>
                 </Box>
                        <Box display="flex" alignItems="center" justifyContent="space-between" mt={0.5}>
                          <Typography 
                            variant="body2" 
                            color="text.secondary" 
                            noWrap
                            sx={{ flex: 1, mr: 1 }}
                          >
                            {conversation.lastMessage}
                          </Typography>
                          {conversation.unreadCount > 0 && (
                            <Chip
                              label={conversation.unreadCount}
                              size="small"
                              sx={{
                                bgcolor: 'primary.main',
                                color: 'white',
                                fontSize: '0.75rem',
                                height: 20,
                                minWidth: 20
                              }}
                            />
                          )}
                 </Box>
               </Box>
                    </ListItemButton>
                    {index < filteredConversations.length - 1 && <Divider />}
                  </React.Fragment>
                ))}
              </List>
            )}
          </Box>
        </Paper>

        {/* Chat Window */}
        <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column', bgcolor: 'white' }}>
          {selectedConversation ? (
            <>
              {/* Chat Header */}
              <Box sx={{ 
                p: 3, 
                borderBottom: '1px solid #e2e8f0',
                bgcolor: 'white',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between'
              }}>
                                <Box display="flex" alignItems="center" gap={2}>
                  <Badge
                    overlap="circular"
                    anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
                    badgeContent={
                <Box
                  sx={{
                          width: 12,
                          height: 12,
                          borderRadius: '50%',
                          bgcolor: selectedConversation.isOnline ? '#10b981' : '#6b7280',
                          border: '2px solid white'
                        }}
                      />
                    }
                  >
                    <Avatar 
                      sx={{ 
                        bgcolor: 'primary.main', 
                        fontWeight: 600,
                        cursor: 'pointer',
                        '&:hover': { opacity: 0.8 }
                      }}
                      onClick={() => navigate(`/user/${selectedConversation.sellerId}`)}
                    >
                      {selectedConversation.avatar}
                    </Avatar>
                  </Badge>
                  <Box>
                    <Typography 
                      variant="h6" 
                      fontWeight={600}
                      sx={{ 
                        cursor: 'pointer',
                        '&:hover': { color: 'primary.main' }
                      }}
                      onClick={() => navigate(`/listing/${selectedConversation.listingId}`)}
                    >
                      {selectedConversation.title}
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      {selectedConversation.isOnline ? 'Online' : 'Offline'} • 
                      {selectedConversation.listingPrice > 0 && ` ${selectedConversation.listingPrice}€`}
                    </Typography>
                  </Box>
                </Box>

                <Box display="flex" gap={1}>
                  <Tooltip title="Videoanruf">
                    <IconButton size="small">
                      <VideocamIcon />
                    </IconButton>
                  </Tooltip>
                  <Tooltip title="Anruf">
                    <IconButton size="small">
                      <PhoneIcon />
                    </IconButton>
                  </Tooltip>
                  <Tooltip title="Info">
                    <IconButton size="small">
                      <InfoIcon />
                    </IconButton>
                  </Tooltip>
                </Box>
              </Box>

              {/* Messages Area */}
              <Box sx={{ 
                flex: 1, 
                overflow: 'auto', 
                p: 2,
                bgcolor: '#f8fafc',
                backgroundImage: 'radial-gradient(circle at 1px 1px, rgba(0,0,0,0.05) 1px, transparent 0)',
                backgroundSize: '20px 20px'
              }}>
                {messages.length === 0 ? (
                  <Box sx={{ 
                    textAlign: 'center', 
                    py: 8,
                display: 'flex',
                    flexDirection: 'column',
                alignItems: 'center',
                    justifyContent: 'center',
                    height: '100%'
                  }}>
                    <Zoom in timeout={800}>
                      <Box>
                        <MessageIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
                        <Typography variant="h6" color="text.secondary" gutterBottom>
                          Noch keine Nachrichten
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          Starte eine Unterhaltung, indem du eine Nachricht sendest.
                        </Typography>
                      </Box>
                    </Zoom>
                  </Box>
                ) : (
                  <Stack spacing={2}>
                    {messages.map((message, index) => (
                      <Slide 
                        key={message.id} 
                        direction={message.isOwn ? "left" : "right"} 
                        in 
                        timeout={300}
                      >
                        <Box sx={{ 
                          display: 'flex', 
                          justifyContent: message.isOwn ? 'flex-end' : 'flex-start',
                          alignItems: 'flex-end',
                          gap: 1
                        }}>
                          {!message.isOwn && (
                            <Avatar sx={{ 
                              width: 32, 
                              height: 32, 
                              bgcolor: 'grey.300',
                              fontSize: '0.875rem'
                            }}>
                              {selectedConversation.avatar}
                            </Avatar>
                          )}
                          <Box sx={{ maxWidth: '70%' }}>
                            <Paper
                              elevation={0}
                              sx={{
                                p: 2,
                                bgcolor: message.isOwn ? 'primary.main' : 'white',
                                color: message.isOwn ? 'white' : 'text.primary',
                                borderRadius: 3,
                                border: message.isOwn ? 'none' : '1px solid #e2e8f0',
                                position: 'relative',
                                '&::before': message.isOwn ? {
                                  content: '""',
                                  position: 'absolute',
                                  bottom: 0,
                                  right: -8,
                                  width: 0,
                                  height: 0,
                                  borderLeft: '8px solid',
                                  borderLeftColor: 'primary.main',
                                  borderTop: '8px solid transparent',
                                  borderBottom: '8px solid transparent'
                                } : {
                                  content: '""',
                                  position: 'absolute',
                                  bottom: 0,
                                  left: -8,
                                  width: 0,
                                  height: 0,
                                  borderRight: '8px solid',
                                  borderRightColor: 'white',
                                  borderTop: '8px solid transparent',
                                  borderBottom: '8px solid transparent'
                                }
                              }}
                            >
                              <Typography variant="body1" sx={{ wordBreak: 'break-word' }}>
                                {message.content}
                              </Typography>
                            </Paper>
                            <Typography 
                              variant="caption" 
                              color="text.secondary" 
                              sx={{ 
                                display: 'block',
                                textAlign: message.isOwn ? 'right' : 'left',
                                mt: 0.5,
                                px: 1
                              }}
                            >
                              {formatTime(message.timestamp)}
                              {message.isOwn && (
                                <CheckCircleIcon 
                                  sx={{ 
                                    fontSize: 14, 
                                    ml: 0.5,
                                    color: message.isRead ? 'primary.main' : 'text.secondary'
                                  }} 
                                />
                              )}
                            </Typography>
                          </Box>
                          {message.isOwn && (
                            <Avatar sx={{ 
                              width: 32, 
                              height: 32, 
                              bgcolor: 'primary.main',
                              fontSize: '0.875rem'
                            }}>
                              {user?.email?.charAt(0).toUpperCase()}
                            </Avatar>
                          )}
                        </Box>
                      </Slide>
                    ))}
                    <div ref={messagesEndRef} />
                  </Stack>
                )}
              </Box>

              {/* Message Input */}
              <Box sx={{ 
                p: 3, 
                borderTop: '1px solid #e2e8f0', 
                bgcolor: 'white'
              }}>
                <Box display="flex" gap={1} alignItems="flex-end">
                  <IconButton onClick={handleFileUpload} size="small">
                    <AttachFileIcon />
                  </IconButton>
                  <TextField
                    fullWidth
                    multiline
                    maxRows={4}
                    placeholder="Nachricht eingeben..."
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' && !e.shiftKey) {
                        e.preventDefault();
                        handleSendMessage();
                      }
                    }}
                    variant="outlined"
                    size="small"
                    sx={{
                      '& .MuiOutlinedInput-root': {
                        borderRadius: 3,
                        bgcolor: '#f8fafc',
                        '&:hover': {
                          bgcolor: '#f1f5f9'
                        },
                        '&.Mui-focused': {
                          bgcolor: 'white'
                        }
                      }
                    }}
                  />
                  <IconButton 
                    onClick={() => setShowEmojiPicker(!showEmojiPicker)}
                    size="small"
                  >
                    <EmojiEmotionsIcon />
                  </IconButton>
                  <Button
                    variant="contained"
                    onClick={handleSendMessage}
                    disabled={!newMessage.trim()}
                    sx={{ 
                      borderRadius: 3,
                      minWidth: 'auto',
                      px: 2,
                      py: 1,
                      boxShadow: '0 2px 8px rgba(25, 118, 210, 0.3)',
                      '&:hover': {
                        boxShadow: '0 4px 12px rgba(25, 118, 210, 0.4)',
                      }
                    }}
                  >
                    <SendIcon />
                  </Button>
                </Box>
              </Box>
            </>
          ) : (
            <Box sx={{ 
              flex: 1, 
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              bgcolor: '#f8fafc'
            }}>
              <Fade in timeout={800}>
                <Box sx={{ textAlign: 'center' }}>
                  <MessageIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
                  <Typography variant="h5" color="text.secondary" gutterBottom>
                    Wähle eine Konversation
                  </Typography>
                  <Typography variant="body1" color="text.secondary">
                    Wähle eine Konversation aus der linken Liste aus, um zu chatten.
                  </Typography>
                </Box>
              </Fade>
              </Box>
            )}
          </Box>
      </Box>

      {/* Context Menu */}
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
        PaperProps={{
          sx: { borderRadius: 2, minWidth: 200 }
        }}
      >
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <ArchiveIcon fontSize="small" />
          </ListItemIcon>
          Alle archivieren
        </MenuItem>
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <DeleteIcon fontSize="small" />
          </ListItemIcon>
          Alle löschen
        </MenuItem>
        <Divider />
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <BlockIcon fontSize="small" />
          </ListItemIcon>
          Blockierte Benutzer
        </MenuItem>
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <ReportIcon fontSize="small" />
          </ListItemIcon>
          Melden
        </MenuItem>
      </Menu>

      {/* Hidden File Input */}
      <input
        type="file"
        ref={fileInputRef}
        style={{ display: 'none' }}
        accept="image/*,.pdf,.doc,.docx"
      />

      {/* Snackbar */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert 
          onClose={() => setSnackbar({ ...snackbar, open: false })} 
          severity={snackbar.severity}
          sx={{ borderRadius: 2 }}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
        </DashboardLayout>
  );
};

import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import {
  Container,
  Typography,
  Box,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  Grid,
  Paper,
  Button,
  FormControlLabel,
  Switch,
  CircularProgress,
  Alert,
  Pagination,
  InputAdornment,
  Tabs,
  Tab,
} from '@mui/material';
import {
  Search,
  LocationOn,
  FilterList,
  Sort,
  Verified,
  Store,
  Business,
  Person,
} from '@mui/icons-material';
import { EntityCard, EntityCardSkeleton } from '../components/EntityCard';
import { adaptShopToEntity, adaptDienstleisterToEntity, adaptUserToEntity, createContactHandlers } from '../adapters/entityAdapters';
import { entitySearchService } from '../services/entitySearchService';

// Lokale Definitionen um Caching-Probleme zu vermeiden
type EntityType = 'all' | 'shops' | 'providers' | 'users';

interface EntitySearchParams {
  type: EntityType;
  search?: string;
  location?: string;
  verified?: boolean;
  sortBy?: 'name' | 'rating' | 'created' | 'verified';
  limit?: number;
  offset?: number;
}

interface TabPanelProps {
  children?: React.ReactNode;
  index: number;
  value: number;
}

function TabPanel(props: TabPanelProps) {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`entity-tabpanel-${index}`}
      aria-labelledby={`entity-tab-${index}`}
      {...other}
    >
      {value === index && <Box sx={{ p: 3 }}>{children}</Box>}
    </div>
  );
}

const EntitySearchPage: React.FC = () => {
  const [urlSearchParams, setUrlSearchParams] = useSearchParams();
  
  // Tab-Mapping
  const tabToType: EntityType[] = ['all', 'shops', 'providers', 'users'];
  const typeToTab: Record<EntityType, number> = { all: 0, shops: 1, providers: 2, users: 3 };
  
  const [searchParams, setSearchParams] = useState<EntitySearchParams>({
    type: (urlSearchParams.get('type') as EntityType) || 'all',
    search: urlSearchParams.get('search') || '',
    location: urlSearchParams.get('location') || '',
    verified: urlSearchParams.get('verified') === 'true' ? true : undefined,
    sortBy: (urlSearchParams.get('sortBy') as any) || 'name',
    limit: 20,
    offset: 0
  });
  
  const [entities, setEntities] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [totalCount, setTotalCount] = useState(0);
  const [hasMore, setHasMore] = useState(false);
  const [stats, setStats] = useState({ shops: 0, providers: 0, users: 0, total: 0 });
  const [tabValue, setTabValue] = useState(typeToTab[searchParams.type]);

  useEffect(() => {
    loadStats();
  }, []);

  useEffect(() => {
    searchEntities();
  }, [searchParams]);

  const loadStats = async () => {
    try {
      const statsData = await entitySearchService.getEntityStats();
      setStats(statsData);
    } catch (error) {
      console.warn('Fehler beim Laden der Statistiken:', error);
    }
  };

  const searchEntities = async () => {
    setLoading(true);
    setError(null);
    
    try {
      const result = await entitySearchService.searchEntities(searchParams);
      setEntities(result.entities);
      setTotalCount(result.totalCount);
      setHasMore(result.hasMore);
    } catch (error) {
      setError('Fehler beim Laden der Daten');
      console.error('Search error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleTabChange = (event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
    setSearchParams(prev => ({
      ...prev,
      type: tabToType[newValue],
      offset: 0
    }));
  };

  const handleSearchChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setSearchParams(prev => ({
      ...prev,
      search: event.target.value,
      offset: 0
    }));
  };

  const handleLocationChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setSearchParams(prev => ({
      ...prev,
      location: event.target.value,
      offset: 0
    }));
  };

  const handleSortChange = (event: any) => {
    setSearchParams(prev => ({
      ...prev,
      sortBy: event.target.value,
      offset: 0
    }));
  };

  const handleVerifiedChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setSearchParams(prev => ({
      ...prev,
      verified: event.target.checked ? true : undefined,
      offset: 0
    }));
  };

  const handlePageChange = (event: React.ChangeEvent<unknown>, page: number) => {
    setSearchParams(prev => ({
      ...prev,
      offset: (page - 1) * (prev.limit || 20)
    }));
  };

  const adaptEntity = (entity: any) => {
    switch (entity._entityType) {
      case 'shop':
        return adaptShopToEntity(entity);
      case 'provider':
        return adaptDienstleisterToEntity(entity);
      case 'user':
        return adaptUserToEntity(entity);
      default:
        return null;
    }
  };

  const contactHandlers = createContactHandlers();

  const renderEntityCards = () => {
    if (loading) {
      return (
        <Grid container spacing={3}>
          {Array.from({ length: 6 }).map((_, index) => (
            <Grid item xs={12} sm={6} md={4} key={index}>
              <EntityCardSkeleton />
            </Grid>
          ))}
        </Grid>
      );
    }

    if (entities.length === 0) {
      return (
        <Box textAlign="center" py={8}>
          <Typography variant="h6" color="text.secondary" gutterBottom>
            Keine Ergebnisse gefunden
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Versuchen Sie andere Suchbegriffe oder Filter
          </Typography>
        </Box>
      );
    }

    return (
      <Grid container spacing={3} sx={{ alignItems: 'stretch', justifyContent: 'center' }}>
        {entities.map((entity) => {
          const adaptedEntity = adaptEntity(entity);
          if (!adaptedEntity) return null;
          
          return (
            <Grid 
              item 
              xs={12} 
              sm={6} 
              md={4} 
              lg={3}
              xl={3}
              key={`${entity._entityType}-${entity.id}`}
              sx={{ 
                display: 'flex',
                justifyContent: 'center',
                maxWidth: '300px !important'
              }}
            >
              <EntityCard
                entity={adaptedEntity}
                onView={contactHandlers.handleView}
                onMessage={contactHandlers.handleMessage}
                onCall={contactHandlers.handleCall}
                onEmail={contactHandlers.handleEmail}
                onWebsite={contactHandlers.handleWebsite}
              />
            </Grid>
          );
        })}
      </Grid>
    );
  };

  const currentPage = Math.floor((searchParams.offset || 0) / (searchParams.limit || 20)) + 1;
  const totalPages = Math.ceil(totalCount / (searchParams.limit || 20));

  return (
    <Container maxWidth="xl" sx={{ py: 4 }}>
      {/* Header */}
      <Box mb={4}>
        <Typography variant="h4" component="h1" gutterBottom>
          Entitäten durchsuchen
        </Typography>
        <Typography variant="body1" color="text.secondary" paragraph>
          Finden Sie Shops, Dienstleister und Benutzer an einem Ort
        </Typography>
        
        {/* Statistiken */}
        <Box display="flex" gap={2} mb={3} flexWrap="wrap">
          <Chip
            icon={<Store />}
            label={`${stats.shops} Shops`}
            color="primary"
            variant="outlined"
          />
          <Chip
            icon={<Business />}
            label={`${stats.providers} Dienstleister`}
            color="secondary"
            variant="outlined"
          />
          <Chip
            icon={<Person />}
            label={`${stats.users} Benutzer`}
            color="success"
            variant="outlined"
          />
          <Chip
            label={`${stats.total} Gesamt`}
            color="default"
            variant="filled"
          />
        </Box>
      </Box>

      {/* Filter und Suche */}
      <Paper sx={{ p: 3, mb: 4 }}>
        <Grid container spacing={3} alignItems="center">
          <Grid item xs={12} md={4}>
            <TextField
              fullWidth
              label="Suchen"
              value={searchParams.search}
              onChange={handleSearchChange}
              placeholder="Name, Beschreibung, Kategorie..."
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Search />
                  </InputAdornment>
                ),
              }}
            />
          </Grid>
          
          <Grid item xs={12} md={3}>
            <TextField
              fullWidth
              label="Standort"
              value={searchParams.location}
              onChange={handleLocationChange}
              placeholder="Stadt, Region..."
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <LocationOn />
                  </InputAdornment>
                ),
              }}
            />
          </Grid>
          
          <Grid item xs={12} md={2}>
            <FormControl fullWidth>
              <InputLabel>Sortierung</InputLabel>
              <Select
                value={searchParams.sortBy}
                onChange={handleSortChange}
                label="Sortierung"
                startAdornment={
                  <InputAdornment position="start">
                    <Sort />
                  </InputAdornment>
                }
              >
                <MenuItem value="name">Name</MenuItem>
                <MenuItem value="rating">Bewertung</MenuItem>
                <MenuItem value="created">Erstellt</MenuItem>
                <MenuItem value="verified">Verifiziert</MenuItem>
              </Select>
            </FormControl>
          </Grid>
          
          <Grid item xs={12} md={3}>
            <FormControlLabel
              control={
                <Switch
                  checked={searchParams.verified === true}
                  onChange={handleVerifiedChange}
                  color="primary"
                />
              }
              label={
                <Box display="flex" alignItems="center" gap={1}>
                  <Verified fontSize="small" />
                  Nur Verifizierte
                </Box>
              }
            />
          </Grid>
        </Grid>
      </Paper>

      {/* Tabs für Entity-Typen */}
      <Box sx={{ borderBottom: 1, borderColor: 'divider', mb: 3 }}>
        <Tabs value={tabValue} onChange={handleTabChange} aria-label="Entity-Typen">
          <Tab 
            label={`Alle (${stats.total})`} 
            icon={<FilterList />}
            iconPosition="start"
          />
          <Tab 
            label={`Shops (${stats.shops})`} 
            icon={<Store />}
            iconPosition="start"
          />
          <Tab 
            label={`Dienstleister (${stats.providers})`} 
            icon={<Business />}
            iconPosition="start"
          />
          <Tab 
            label={`Benutzer (${stats.users})`} 
            icon={<Person />}
            iconPosition="start"
          />
        </Tabs>
      </Box>

      {/* Ergebnisse */}
      {error && (
        <Alert severity="error" sx={{ mb: 3 }}>
          {error}
        </Alert>
      )}

      {renderEntityCards()}

      {/* Pagination */}
      {totalPages > 1 && (
        <Box display="flex" justifyContent="center" mt={4}>
          <Pagination
            count={totalPages}
            page={currentPage}
            onChange={handlePageChange}
            color="primary"
            size="large"
            showFirstButton
            showLastButton
          />
        </Box>
      )}

      {/* Ergebnisse-Info */}
      {!loading && entities.length > 0 && (
        <Box textAlign="center" mt={3}>
          <Typography variant="body2" color="text.secondary">
            Zeige {entities.length} von {totalCount} Ergebnissen
          </Typography>
        </Box>
      )}
    </Container>
  );
};

