          >
            Entdecken Sie spannende Events in Ihrer Nähe oder erstellen Sie Ihre eigene Veranstaltung
          </Typography>
        </Box>

        {/* Search and Filters */}
        <Box sx={{ mb: { xs: 3, md: 4 } }}>
          {isMobile ? (
            // Mobile Layout
            <Box>
              <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                <TextField
                  fullWidth
                  placeholder="Events suchen..."
                  value={searchQuery}
                  onChange={handleSearchChange}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      borderRadius: 2,
                      bgcolor: '#ffffff'
                    }
                  }}
                />
                <IconButton
                  onClick={() => setShowFilters(!showFilters)}
                  sx={{
                    bgcolor: '#f8f9fa',
                    border: '1px solid #e1e8ed',
                    '&:hover': { bgcolor: '#e9ecef' }
                  }}
                >
                  <FilterIcon />
                </IconButton>
              </Box>
              
              {showFilters && (
                <Box sx={{ 
                  display: 'grid',
                  gridTemplateColumns: '1fr 1fr',
                  gap: 2,
                  p: 2,
                  bgcolor: '#f8f9fa',
                  borderRadius: 2,
                  border: '1px solid #e1e8ed'
                }}>
                  <TextField
                    select
                    label="Kategorie"
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                    size="small"
                    sx={{ bgcolor: '#ffffff' }}
                  >
                    <MenuItem value="all">Alle Kategorien</MenuItem>
                    <MenuItem value="music">Musik</MenuItem>
                    <MenuItem value="sports">Sport</MenuItem>
                    <MenuItem value="culture">Kultur</MenuItem>
                    <MenuItem value="business">Business</MenuItem>
                    <MenuItem value="food">Essen & Trinken</MenuItem>
                  </TextField>
                  <TextField
                    select
                    label="Standort"
                    value={selectedLocation}
                    onChange={(e) => setSelectedLocation(e.target.value)}
                    size="small"
                    sx={{ bgcolor: '#ffffff' }}
                  >
                    <MenuItem value="">Alle Standorte</MenuItem>
                    <MenuItem value="berlin">Berlin</MenuItem>
                    <MenuItem value="hamburg">Hamburg</MenuItem>
                    <MenuItem value="munich">München</MenuItem>
                    <MenuItem value="cologne">Köln</MenuItem>
                  </TextField>
                </Box>
              )}
            </Box>
          ) : (
