                  <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 2 }}>
                    {event.tags.slice(0, 3).map((tag: string, index: number) => (
                      <Chip
                        key={index}
                        label={tag}
                        size="small"
                        sx={{
                          bgcolor: '#f8f9fa',
                          color: '#667eea',
                          fontSize: '0.75rem',
                          height: 24
                        }}
                      />
                    ))}
                    {event.tags.length > 3 && (
                      <Chip
                        label={`+${event.tags.length - 3}`}
                        size="small"
                        sx={{
                          bgcolor: '#f8f9fa',
                          color: '#667eea',
                          fontSize: '0.75rem',
                          height: 24
                        }}
                      />
                    )}
                  </Box>

                  <Box sx={{ display: 'flex', gap: 1 }}>
                    <Button
                      variant="outlined"
                      size="small"
                      fullWidth
                      onClick={() => handleContact(event)}
                      sx={{
                        borderColor: '#667eea',
                        color: '#667eea',
                        '&:hover': {
                          bgcolor: '#667eea',
                          color: 'white'
                        }
                      }}
                    >
                      Kontakt
                    </Button>
                    <Button
                      variant="contained"
                      size="small"
                      fullWidth
                      onClick={() => handleEventClick(event.id)}
                      sx={{
                        bgcolor: '#667eea',
                        '&:hover': { bgcolor: '#5a6fd8' }
                      }}
                    >
                      Details
                    </Button>
                  </Box>
                </CardContent>
              </Card>
            ))}
          </Box>
        )}

        {/* Pagination */}
        {!loading && filteredEvents.length > 0 && (
          <Box sx={{ display: 'flex', justifyContent: 'center' }}>
            <Pagination
              count={Math.ceil(filteredEvents.length / 12)}
              page={currentPage}
              onChange={(e, page) => setCurrentPage(page)}
              size={isMobile ? 'small' : 'medium'}
              sx={{
                '& .MuiPaginationItem-root': {
                  borderRadius: 1
                }
              }}
            />
          </Box>
        )}

        {/* No Results */}
        {!loading && filteredEvents.length === 0 && (
          <Box sx={{ 
            textAlign: 'center', 
            py: { xs: 6, md: 8 },
            color: '#7f8c8d'
          }}>
            <EventIcon sx={{ fontSize: { xs: '4rem', md: '6rem' }, mb: 2, opacity: 0.5 }} />
            <Typography 
              variant={isMobile ? 'h6' : 'h5'} 
              sx={{ mb: 1, fontWeight: 500 }}
            >
              Keine Events gefunden
            </Typography>
            <Typography variant="body2">
              Versuche es mit anderen Suchkriterien oder erstelle dein eigenes Event.
            </Typography>
          </Box>
        )}
      </Container>
    </Box>
  );
};

