  const [priceMax, setPriceMax] = useState('');
  const [conditionValue, setConditionValue] = useState('');
  const [categoryValue, setCategoryValue] = useState('');
  const [sortValue, setSortValue] = useState('relevance');
  const [showAdvancedSearch, setShowAdvancedSearch] = useState(false);

  // Data States
  const [listings, setListings] = useState<KleinanzeigenListing[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [totalOffers, setTotalOffers] = useState(0);

  const [locations, setLocations] = useState<string[]>([]);
  const [categories, setCategories] = useState<string[]>([]);
  const [priceOptions, setPriceOptions] = useState<number[]>([]);
  const [conditions, setConditions] = useState<string[]>([]);

  useEffect(() => {
    fetchKleinanzeigen();
    initializeFilterOptions();
  }, []);

  const initializeFilterOptions = () => {
    setLocations(['Berlin', 'Hamburg', 'München', 'Köln', 'Frankfurt', 'Stuttgart', 'Düsseldorf', 'Leipzig', 'Dortmund', 'Essen']);
    setCategories(['Elektronik', 'Mode', 'Haus & Garten', 'Sport & Freizeit', 'Auto & Motorrad', 'Immobilien', 'Jobs', 'Dienstleistungen']);
    setPriceOptions([100, 250, 500, 1000, 2500, 5000, 10000, 25000, 50000, 100000]);
    setConditions(['Neu', 'Gebraucht', 'Defekt']);
  };

  const fetchKleinanzeigen = async (filters: Record<string, any> = {}) => {
    try {
      setLoading(true);
      setError(null);

      // Lade echte Daten vom Backend
      const response = await fetch('http://localhost:8000/api/listings?category=kleinanzeigen');
      const data = await response.json();

      if (data && Array.isArray(data)) {
        // Verarbeite die Bilder für jedes Listing
        const processedListings = data.map((listing: any) => {
          let parsedImages: string[] = [];
          try {
            if (listing.images && Array.isArray(listing.images) && listing.images.length > 0) {
              // images ist bereits ein Array, kein String
              parsedImages = listing.images.map((imagePath: string) => {
                if (imagePath.startsWith('/uploads/')) {
                  return `http://localhost:8000/api/images/${imagePath.replace('/uploads/', '')}`;
                }
                return imagePath;
              });
            }
          } catch (error) {
            console.warn('Fehler beim Verarbeiten der Bilder für Listing:', listing.id, error);
          }

          // Fallback-Bild wenn keine Bilder vorhanden
          if (parsedImages.length === 0) {
            parsedImages = [PLACEHOLDER_IMAGE_URL];
          }

          return {
            id: listing.id,
            title: listing.title,
            location: listing.location,
            price: listing.price,
            images: parsedImages,
            category: listing.category,
            condition: listing.condition || 'Gebraucht'
          };
        });

        setListings(processedListings);
        setTotalOffers(processedListings.length);
      } else {
        setListings([]);
        setTotalOffers(0);
      }

      setLoading(false);
    } catch (err) {
      console.error('Fehler beim Laden der Anzeigen:', err);
      setError('Fehler beim Laden der Anzeigen');
      setListings([]);
      setTotalOffers(0);
      setLoading(false);
    }
  };

  const handleSearch = () => {
    const filters = {
      search: searchQuery,
      location: locationValue,
      priceMin,
      priceMax,
      condition: conditionValue,
      category: categoryValue,
      sort: sortValue
    };
    fetchKleinanzeigen(filters);
  };

  const handleClearFilters = () => {
    setSearchQuery('');
    setLocationValue('');
    setPriceMin('');
    setPriceMax('');
    setConditionValue('');
    setCategoryValue('');
    setSortValue('relevance');
    fetchKleinanzeigen();
