            <Tab label="System" />
          </Tabs>
        </Paper>

        {/* Notifications List */}
        <Paper 
          elevation={0} 
          sx={{ 
            border: '1px solid',
            borderColor: 'divider',
            borderRadius: 3,
            overflow: 'hidden'
          }}
        >
          {loading ? (
            // Loading skeletons
            <Box sx={{ p: 2 }}>
              {[1, 2, 3].map((item) => (
                <Box key={item} sx={{ mb: 2 }}>
                  <Box sx={{ display: 'flex', gap: 2, alignItems: 'flex-start' }}>
                    <Skeleton variant="circular" width={48} height={48} />
                    <Box sx={{ flex: 1 }}>
                      <Skeleton variant="text" width="60%" height={24} />
                      <Skeleton variant="text" width="80%" height={20} />
                      <Skeleton variant="text" width="40%" height={16} />
                    </Box>
                  </Box>
                </Box>
              ))}
            </Box>
          ) : filteredNotifications.length === 0 ? (
            // Empty state
            <Box sx={{ 
              p: { xs: 4, md: 8 }, 
              textAlign: 'center',
              bgcolor: 'background.paper'
            }}>
              <Box sx={{
                width: 80,
                height: 80,
                borderRadius: '50%',
                bgcolor: 'grey.100',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                mx: 'auto',
                mb: 3
              }}>
                <NotificationsIcon sx={{ fontSize: 40, color: 'grey.400' }} />
              </Box>
              <Typography variant="h5" color="text.secondary" sx={{ mb: 2, fontWeight: 600 }}>
                Keine Benachrichtigungen
              </Typography>
              <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
                {filterType === 'all' 
                  ? 'Du hast noch keine Benachrichtigungen erhalten.'
                  : `Keine ${filterType === 'unread' ? 'ungelesenen' : filterType === 'read' ? 'gelesenen' : filterType} Benachrichtigungen.`
                }
              </Typography>
              <Button
                variant="outlined"
                onClick={() => navigate('/')}
                sx={{
                  borderColor: 'primary.main',
                  color: 'primary.main',
                  '&:hover': {
                    bgcolor: 'primary.main',
                    color: 'white'
                  }
                }}
              >
                Zur Startseite
              </Button>
            </Box>
          ) : (
            // Notifications list
            <List sx={{ p: 0 }}>
              {filteredNotifications.map((notification, index) => (
                <Fade key={notification.id} in={true} timeout={300}>
                  <Box>
                    <ListItem
                      onClick={() => handleNotificationClick(notification)}
                      sx={{
                        bgcolor: notification.read ? 'transparent' : 'rgba(59, 130, 246, 0.05)',
                        cursor: 'pointer',
                        '&:hover': {
                          bgcolor: notification.read ? 'rgba(0, 0, 0, 0.02)' : 'rgba(59, 130, 246, 0.08)'
                        },
                        transition: 'all 0.2s ease',
                        px: { xs: 2, md: 3 },
                        py: { xs: 2, md: 2.5 }
                      }}
                    >
                      <ListItemAvatar>
                        <Avatar 
                          sx={{ 
                            bgcolor: `${getTypeColor(notification.type)}15`,
                            color: getTypeColor(notification.type),
                            width: { xs: 40, md: 48 },
                            height: { xs: 40, md: 48 },
                            fontSize: { xs: '1.1rem', md: '1.3rem' }
                          }}
                        >
                          {getNotificationIcon(notification.type)}
                        </Avatar>
                      </ListItemAvatar>

                      <ListItemText
                        primary={
                          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5 }}>
                            <Typography 
                              variant={isMobile ? "subtitle1" : "h6"}
                              sx={{ 
                                fontWeight: notification.read ? 500 : 700,
                                color: notification.read ? 'text.secondary' : 'text.primary',
                                flex: 1
                              }}
                            >
                              {notification.title}
                            </Typography>

                            <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
                              <Chip
                                label={notification.priority}
                                size="small"
                                sx={{
                                  bgcolor: `${getPriorityColor(notification.priority)}15`,
                                  color: getPriorityColor(notification.priority),
                                  fontSize: '0.7rem',
                                  fontWeight: 600,
                                  height: 20
                                }}
                              />

                              {!notification.read && (
                                <Chip
                                  label="Neu"
                                  size="small"
                                  sx={{
                                    bgcolor: 'primary.main',
                                    color: 'white',
                                    fontSize: '0.7rem',
                                    fontWeight: 600,
                                    height: 20
                                  }}
                                />
                              )}
                            </Box>
                          </Box>
                        }
                        secondary={
                          <Box>
                            <Typography 
                              variant="body2" 
                              color="text.secondary"
                              sx={{ 
                                mb: 1,
                                lineHeight: 1.5,
                                fontSize: '0.875rem'
                              }}
                            >
                              {notification.message}
                            </Typography>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                              <Typography 
                                variant="caption" 
                                color="text.disabled"
                                sx={{ fontSize: '0.75rem' }}
                              >
                                {formatTimestamp(notification.timestamp)}
                              </Typography>
                              <Typography 
                                variant="caption" 
                                color="text.disabled"
                                sx={{ fontSize: '0.75rem' }}
                              >
                                von {notification.sender}
                              </Typography>
                            </Box>
                          </Box>
                        }
                      />

                      <Box sx={{ 
                        display: 'flex', 
                        gap: 1, 
                        alignItems: 'center',
                        ml: 2
                      }}>
                        {!notification.read && (
                          <Tooltip title="Als gelesen markieren">
                            <IconButton
                              size="small"
                              onClick={(e) => {
                                e.stopPropagation();
                                markAsRead(notification.id);
                              }}
                              sx={{ 
                                color: 'primary.main',
                                '&:hover': {
                                  bgcolor: 'primary.main',
                                  color: 'white'
                                }
                              }}
                            >
                              <CheckCircleIcon fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        )}

                        <Tooltip title="Löschen">
                          <IconButton
                            size="small"
                            onClick={(e) => {
                              e.stopPropagation();
                              deleteNotification(notification.id);
                            }}
                            sx={{ 
                              color: 'error.main',
                              '&:hover': {
                                bgcolor: 'error.main',
                                color: 'white'
                              }
                            }}
                          >
                            <DeleteIcon fontSize="small" />
                          </IconButton>
                        </Tooltip>
                      </Box>
                    </ListItem>

                    {index < filteredNotifications.length - 1 && (
                      <Divider sx={{ mx: 3 }} />
                    )}
                  </Box>
                </Fade>
              ))}
            </List>
          )}
        </Paper>
      </Container>

      {/* Mobile FAB for quick actions */}
      {isMobile && (
        <Fab
          color="primary"
          aria-label="Benachrichtigungen aktualisieren"
          onClick={refreshNotifications}
          disabled={loading}
          sx={{
            position: 'fixed',
            bottom: 20,
            right: 20,
            zIndex: 1000
          }}
        >
          <RefreshIcon />
        </Fab>
      )}
    </Box>
  );
};

