export type EntityType = 'shop' | 'provider' | 'user';

export interface EntityRating {
  value: number;
  count: number;
}

export interface EntityContact {
  phone?: string;
  email?: string;
  website?: string;
}

export interface EntityLinks {
  view?: string;
  message?: string;
}

export interface EntityBadges {
  verified?: boolean;
  certified?: boolean;
  recommended?: boolean;
}

// Basis-Entity-Interface
export interface BaseEntity {
  id: string | number;
  type: EntityType;
  name: string;
  subtitle?: string; // Branche/Position/Firma
  avatarUrl?: string;
  initials?: string;
  location?: string;
  description?: string;
  tags?: string[]; // max. 5 sichtbar
  rating?: EntityRating;
  badges: EntityBadges;
