// Analytics System für User Behavior Tracking

interface AnalyticsEvent {
  event: string;
  properties: Record<string, unknown>;
  timestamp: number;
  sessionId: string;
}

interface SearchAnalytics {
  category: string;
  filters_used: number;
  search_depth: number;
  search_duration: number;
  results_count?: number;
}

class Analytics {
  private sessionId: string;
  private events: AnalyticsEvent[] = [];
  private searchStartTime: number | null = null;

  constructor() {
    this.sessionId = this.generateSessionId();
    this.initializeAnalytics();
  }

  private generateSessionId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  private initializeAnalytics(): void {
    // Track page views
    this.track('page_view', {
      url: window.location.href,
      user_agent: navigator.userAgent,
      screen_resolution: `${screen.width}x${screen.height}`
    });

    // Track performance metrics
    this.trackPerformance();
  }

  private trackPerformance(): void {
    if ('performance' in window) {
      const navigation = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;
      
      this.track('performance_metrics', {
        page_load_time: navigation.loadEventEnd - navigation.loadEventStart,
        dom_content_loaded: navigation.domContentLoadedEventEnd - navigation.domContentLoadedEventStart,
        first_paint: performance.getEntriesByName('first-paint')[0]?.startTime || 0,
        first_contentful_paint: performance.getEntriesByName('first-contentful-paint')[0]?.startTime || 0
      });
    }
  }

  public track(event: string, properties: Record<string, unknown> = {}): void {
    const analyticsEvent: AnalyticsEvent = {
      event,
      properties: {
        ...properties,
        timestamp: Date.now(),
        session_id: this.sessionId
      },
      timestamp: Date.now(),
      sessionId: this.sessionId
    };

    this.events.push(analyticsEvent);
    
    // In production, send to analytics service
    if (process.env.NODE_ENV === 'production') {
      this.sendToAnalyticsService(analyticsEvent);
    } else {
      console.log('Analytics Event:', analyticsEvent);
    }
  }

  public trackSearchBehavior(searchData: Record<string, unknown>): void {
    const filtersUsed = Object.keys(searchData).filter(key => 
      searchData[key] && searchData[key] !== ''
    ).length;

    const searchDepth = this.calculateSearchDepth(searchData);

    const analytics: SearchAnalytics = {
      category: (searchData.category as string) || 'unknown',
      filters_used: filtersUsed,
      search_depth: searchDepth,
      search_duration: this.searchStartTime ? Date.now() - this.searchStartTime : 0
    };

    this.track('search_performed', analytics as unknown as Record<string, unknown>);
  }

  private calculateSearchDepth(searchData: Record<string, unknown>): number {
    let depth = 0;
    
    // Kategorien
    if (searchData.category) depth += 1;
    if (searchData.location) depth += 1;
    if (searchData.date) depth += 1;
    
    // Spezifische Filter
    if (searchData.priceRange) depth += 1;
    if (searchData.condition) depth += 1;
    if (searchData.accommodationType) depth += 1;
    if (searchData.carType) depth += 1;
    if (searchData.transmission) depth += 1;
    if (searchData.extras && Array.isArray(searchData.extras)) depth += searchData.extras.length;
    
    return depth;
  }

  public startSearchTracking(): void {
    this.searchStartTime = Date.now();
  }

  public trackUserInteraction(element: string, action: string, properties: Record<string, unknown> = {}): void {
    this.track('user_interaction', {
      element,
      action,
      ...properties
    });
  }

  public trackError(error: Error, context: string): void {
    this.track('error', {
      message: error.message,
      stack: error.stack,
      context,
      url: window.location.href
    });
  }

  public trackConversion(conversionType: string, value?: number): void {
    this.track('conversion', {
      type: conversionType,
      value,
      currency: 'EUR'
    });
  }

  private sendToAnalyticsService(event: AnalyticsEvent): void {
    // In production, send to your analytics service
    // Example: Google Analytics, Mixpanel, etc.
    fetch('/api/analytics', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(event)
    }).catch(error => {
      console.error('Failed to send analytics event:', error);
    });
  }

  public getEvents(): AnalyticsEvent[] {
    return this.events;
  }

  public clearEvents(): void {
    this.events = [];
  }
}

// Global analytics instance
export const analytics = new Analytics();

// Hook für React Components
export function useAnalytics() {
  const trackEvent = (event: string, properties: Record<string, unknown> = {}) => {
    analytics.track(event, properties);
  };

  const trackSearch = (searchData: Record<string, unknown>) => {
    analytics.trackSearchBehavior(searchData);
  };

  const trackInteraction = (element: string, action: string, properties: Record<string, unknown> = {}) => {
    analytics.trackUserInteraction(element, action, properties);
  };

  const startSearchTracking = () => {
    analytics.startSearchTracking();
  };

  return {
    trackEvent,
    trackSearch,
    trackInteraction,
    startSearchTracking
  };
}

// Performance Monitoring
export class PerformanceMonitor {
  private static instance: PerformanceMonitor;
  private metrics: Map<string, number[]> = new Map();

  static getInstance(): PerformanceMonitor {
    if (!PerformanceMonitor.instance) {
      PerformanceMonitor.instance = new PerformanceMonitor();
    }
    return PerformanceMonitor.instance;
  }

  startTimer(name: string): () => void {
    const startTime = performance.now();
    
    return () => {
      const duration = performance.now() - startTime;
      this.recordMetric(name, duration);
    };
  }

  private recordMetric(name: string, value: number): void {
    if (!this.metrics.has(name)) {
      this.metrics.set(name, []);
    }
    this.metrics.get(name)!.push(value);
  }

  getAverageMetric(name: string): number {
    const values = this.metrics.get(name);
    if (!values || values.length === 0) return 0;
    return values.reduce((a, b) => a + b, 0) / values.length;
  }

  getMetrics(): Record<string, number> {
    const result: Record<string, number> = {};
    for (const [name, values] of this.metrics.entries()) {
      result[name] = this.getAverageMetric(name);
    }
    return result;
  }
}

export const performanceMonitor = PerformanceMonitor.getInstance();

import { getFullApiUrl } from '@/config/config';
import { logger } from './logger';

export interface User {
  id: string;
  email: string;
  username: string;
  role: 'user' | 'admin' | 'moderator';
  isActive: boolean;
  createdAt: string;
  avatar?: string;
}

export interface AuthResponse {
  access_token: string;
  token_type: string;
  user: User;
}

export const authUtils = {
  async checkTokenValidity(): Promise<boolean> {
    const token = localStorage.getItem('token');
    if (!token) return false;

    try {
      const response = await fetch(getFullApiUrl('api/me'), {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        localStorage.removeItem('token');
        return false;
      }

      return true;
    } catch (error) {
      logger.error('Token validation error', error);
      localStorage.removeItem('token');
      return false;
    }
  },

  async autoRelogin(): Promise<boolean> {
    const token = localStorage.getItem('token');
    if (!token) return false;

    try {
      const response = await fetch(getFullApiUrl('api/me'), {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const userData = await response.json();
        localStorage.setItem('user', JSON.stringify(userData));
        return true;
      }

      return false;
    } catch (error) {
      logger.error('Auto relogin failed', error);
      return false;
    }
  },

  async manualLogin(email: string, password: string): Promise<boolean> {
    try {
      const response = await fetch(getFullApiUrl('api/auth/login'), {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ email, password })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Login failed');
      }

      const data: AuthResponse = await response.json();

      localStorage.setItem('token', data.access_token);
      localStorage.setItem('user', JSON.stringify(data.user));

      return true;
    } catch (error) {
      logger.error('Manual login failed', error);
      return false;
    }
  },

  logout(): void {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
  },

  getValidToken(): string | null {
    const token = localStorage.getItem('token');
    return token || null;
  },

  getCurrentUser(): User | null {
    const userStr = localStorage.getItem('user');
    if (!userStr) return null;

    try {
      return JSON.parse(userStr) as User;
    } catch (error) {
      logger.error('Failed to parse user data', error);
      return null;
    }
  },

  isAuthenticated(): boolean {
    return !!this.getValidToken();
  },

  isAdmin(): boolean {
    const user = this.getCurrentUser();
    return user?.role === 'admin';
  },

  isModerator(): boolean {
    const user = this.getCurrentUser();
    return user?.role === 'moderator' || user?.role === 'admin';
  }
};

// Einfaches Caching-System für API-Aufrufe
interface CacheEntry<T> {
  data: T;
  timestamp: number;
  ttl: number; // Time to live in milliseconds
}

class APICache {
  private cache = new Map<string, CacheEntry<unknown>>();
  private defaultTTL = 5 * 60 * 1000; // 5 Minuten

  set<T>(key: string, data: T, ttl: number = this.defaultTTL): void {
    this.cache.set(key, {
      data,
      timestamp: Date.now(),
      ttl
    });
  }

  get<T>(key: string): T | null {
    const entry = this.cache.get(key);
    if (!entry) return null;

    const isExpired = Date.now() - entry.timestamp > entry.ttl;
    if (isExpired) {
      this.cache.delete(key);
      return null;
    }

    return entry.data as T;
  }

  has(key: string): boolean {
    return this.get(key) !== null;
  }

  delete(key: string): void {
    this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }

  // Cache-Schlüssel für verschiedene Endpoints
  static keys = {
    categories: 'api:categories',
    listings: 'api:listings',
    userFavorites: (userId: string) => `api:favorites:${userId}`,
    listing: (id: string) => `api:listing:${id}`,
    userListings: (userId: string) => `api:user-listings:${userId}`,
  };
}

export const apiCache = new APICache();

// Hilfsfunktionen für gecachte API-Aufrufe
export const cachedFetch = async <T>(
  url: string, 
  cacheKey: string, 
  ttl: number = 5 * 60 * 1000
): Promise<T> => {
  // Prüfe Cache
  const cached = apiCache.get<T>(cacheKey);
  if (cached) {
    return cached;
  }

  // API-Aufruf
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`HTTP ${response.status}: ${response.statusText}`);
  }

  const data = await response.json();
  
  // Cache setzen
  apiCache.set(cacheKey, data, ttl);
  
  return data;
};

// Cache invalidieren
export const invalidateCache = (pattern: string): void => {
  const keys = Array.from(apiCache['cache'].keys());
  keys.forEach(key => {
    if (key.includes(pattern)) {
      apiCache.delete(key);
    }
  });
};

/**
 * Allgemeine Hilfsfunktionen für die Anwendung
 */

/**
 * Generiert eine zufällige ID
 */
export function generateId(): string {
  return Math.random().toString(36).substr(2, 9) + Date.now().toString(36);
}

/**
 * Generiert eine zufällige ID mit Prefix
 */
export function generateIdWithPrefix(prefix: string): string {
  return `${prefix}_${generateId()}`;
}

/**
 * Formatiert eine Zahl als Währung
 */
export function formatCurrency(amount: number, currency = 'EUR', locale = 'de-DE'): string {
  return new Intl.NumberFormat(locale, {
    style: 'currency',
    currency
  }).format(amount);
}

/**
 * Formatiert eine Zahl mit Tausendertrennzeichen
 */
export function formatNumber(num: number, locale = 'de-DE'): string {
  return new Intl.NumberFormat(locale).format(num);
}

/**
 * Formatiert einen Prozentsatz
 */
export function formatPercentage(value: number, decimals = 1): string {
  return `${value.toFixed(decimals)}%`;
}

/**
 * Formatiert eine Datei-Größe
 */
export function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 Bytes';
  
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

/**
 * Formatiert eine Zeitspanne in Sekunden
 */
export function formatDuration(seconds: number): string {
  if (seconds < 60) return `${seconds}s`;
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ${seconds % 60}s`;
  
  const hours = Math.floor(seconds / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const remainingSeconds = seconds % 60;
  
  return `${hours}h ${minutes}m ${remainingSeconds}s`;
}

/**
 * Formatiert eine Zeitspanne in Millisekunden
 */
export function formatDurationMs(milliseconds: number): string {
  return formatDuration(Math.floor(milliseconds / 1000));
}

/**
 * Prüft ob ein Wert leer ist
 */
export function isEmpty(value: unknown): boolean {
  if (value === null || value === undefined) return true;
  if (typeof value === 'string') return value.trim().length === 0;
  if (Array.isArray(value)) return value.length === 0;
  if (typeof value === 'object') return Object.keys(value).length === 0;
  return false;
}

/**
 * Prüft ob ein Wert nicht leer ist
 */
export function isNotEmpty(value: unknown): boolean {
  return !isEmpty(value);
}

/**
 * Entfernt leere Werte aus einem Objekt
 */
export function removeEmptyValues<T extends Record<string, unknown>>(obj: T): Partial<T> {
  const result: Partial<T> = {};
  
  for (const [key, value] of Object.entries(obj)) {
    if (isNotEmpty(value)) {
      (result as Record<string, unknown>)[key] = value;
    }
  }
  
  return result;
}

/**
 * Entfernt leere Werte aus einem Array
 */
export function removeEmptyArrayValues<T>(arr: T[]): T[] {
  return arr.filter(item => isNotEmpty(item));
}

/**
 * Gruppiert Array-Elemente nach einem Schlüssel
 */
export function groupBy<T>(array: T[], key: keyof T): Record<string, T[]> {
  return array.reduce((groups, item) => {
    const groupKey = String(item[key]);
    if (!groups[groupKey]) {
      groups[groupKey] = [];
    }
    groups[groupKey].push(item);
    return groups;
  }, {} as Record<string, T[]>);
}

/**
 * Sortiert Array-Elemente nach einem Schlüssel
 */
export function sortBy<T>(array: T[], key: keyof T, direction: 'asc' | 'desc' = 'asc'): T[] {
  return [...array].sort((a, b) => {
    const aVal = a[key];
    const bVal = b[key];
    
    if (aVal < bVal) return direction === 'asc' ? -1 : 1;
    if (aVal > bVal) return direction === 'asc' ? 1 : -1;
    return 0;
  });
}

/**
 * Entfernt Duplikate aus einem Array
 */
export function unique<T>(array: T[]): T[] {
  return Array.from(new Set(array));
}

/**
 * Entfernt Duplikate aus einem Array basierend auf einem Schlüssel
 */
export function uniqueBy<T>(array: T[], key: keyof T): T[] {
  const seen = new Set();
  return array.filter(item => {
    const value = item[key];
    if (seen.has(value)) {
      return false;
    }
    seen.add(value);
    return true;
  });
}

/**
 * Teilt ein Array in Chunks auf
 */
export function chunk<T>(array: T[], size: number): T[][] {
  const chunks: T[][] = [];
  for (let i = 0; i < array.length; i += size) {
    chunks.push(array.slice(i, i + size));
  }
  return chunks;
}

/**
 * Verzögert die Ausführung einer Funktion
 */
export function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Debounced Funktion
 */
export function debounce<T extends (...args: unknown[]) => unknown>(
  func: T,
  wait: number
): (...args: Parameters<T>) => void {
  let timeout: NodeJS.Timeout;
  
  return (...args: Parameters<T>) => {
    clearTimeout(timeout);
    timeout = setTimeout(() => func(...args), wait);
  };
}

/**
 * Throttled Funktion
 */
export function throttle<T extends (...args: unknown[]) => unknown>(
  func: T,
  limit: number
): (...args: Parameters<T>) => void {
  let inThrottle: boolean;
  
  return (...args: Parameters<T>) => {
    if (!inThrottle) {
      func(...args);
      inThrottle = true;
      setTimeout(() => inThrottle = false, limit);
    }
  };
}

/**
 * Prüft ob ein Objekt ein bestimmtes Schema hat
 */
export function hasSchema(obj: unknown, schema: Record<string, string>): boolean {
  if (typeof obj !== 'object' || obj === null) return false;
  
  for (const [key, expectedType] of Object.entries(schema)) {
    if (!(key in obj)) return false;
    
    const actualType = typeof (obj as Record<string, unknown>)[key];
    if (actualType !== expectedType) return false;
  }
  
  return true;
}

/**
 * Tiefe Kopie eines Objekts
 */
export function deepClone<T>(obj: T): T {
  if (obj === null || typeof obj !== 'object') return obj;
  if (obj instanceof Date) return new Date(obj.getTime()) as unknown as T;
  if (obj instanceof Array) return obj.map(item => deepClone(item)) as unknown as T;
  if (typeof obj === 'object') {
    const clonedObj = {} as T;
    for (const key in obj) {
      if (obj.hasOwnProperty(key)) {
        clonedObj[key] = deepClone(obj[key]);
      }
    }
    return clonedObj;
  }
  return obj;
}

/**
 * Mischt ein Array
 */
export function shuffle<T>(array: T[]): T[] {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

/**
 * Wählt ein zufälliges Element aus einem Array
 */
export function randomChoice<T>(array: T[]): T | undefined {
  if (array.length === 0) return undefined;
  return array[Math.floor(Math.random() * array.length)];
}

/**
 * Wählt mehrere zufällige Elemente aus einem Array
 */
export function randomChoices<T>(array: T[], count: number): T[] {
  if (count >= array.length) return shuffle(array);
  
  const shuffled = shuffle(array);
  return shuffled.slice(0, count);
}

/**
 * Zentrale Funktionen für Bild-URLs mit intelligentem Fallback
 */

const API_BASE_URL = 'http://localhost:8000';

/**
 * Erstellt eine Bild-URL mit Fallback auf den neuen intelligenten Endpunkt
 * @param imagePath - Der Bildpfad (kann mit /uploads/ beginnen oder nur der Dateiname sein)
 * @returns Vollständige URL zum Bild
 */
export const getImageUrl = (imagePath: string): string => {
  console.log(`getImageUrl called with: "${imagePath}"`);
  
  if (!imagePath) {
    console.log('No imagePath, returning placeholder');
    return '/images/noimage.jpeg';
  }

  // Wenn es bereits eine absolute URL ist, verwende sie direkt
  if (imagePath.startsWith('http')) {
    console.log('Absolute URL, returning as-is');
    return imagePath;
  }

  // Wenn es der Platzhalter ist, verwende ihn direkt
  if (imagePath === '/images/noimage.jpeg' || imagePath === 'noimage.jpeg') {
    console.log('Placeholder detected, returning as-is');
    return '/images/noimage.jpeg';
  }

  // Entferne verschiedene Präfixe falls vorhanden
  let cleanPath = imagePath;
  
  // Entferne /api/uploads/ Präfix
  if (cleanPath.startsWith('/api/uploads/')) {
    cleanPath = cleanPath.replace('/api/uploads/', '');
  }
  // Entferne /uploads/ Präfix
  else if (cleanPath.startsWith('/uploads/')) {
    cleanPath = cleanPath.replace('/uploads/', '');
  }
  // Entferne api/uploads/ Präfix (ohne führenden Schrägstrich)
  else if (cleanPath.startsWith('api/uploads/')) {
    cleanPath = cleanPath.replace('api/uploads/', '');
  }
  
  const finalUrl = `${API_BASE_URL}/api/images/${cleanPath}`;
  
  console.log(`Final URL: ${finalUrl}`);
  return finalUrl;
};

/**
 * Erstellt eine Bild-URL für den Upload-Endpunkt (für neue Uploads)
 * @param filename - Der Dateiname
 * @returns Vollständige URL zum Upload
 */
export const getUploadUrl = (filename: string): string => {
  return `${API_BASE_URL}/uploads/${filename}`;
};

/**
 * Prüft ob ein Bildpfad gültig ist
 * @param imagePath - Der zu prüfende Bildpfad
 * @returns true wenn der Pfad gültig ist
 */
export const isValidImagePath = (imagePath: string | boolean): boolean => {
  return typeof imagePath === 'string' && imagePath.trim().length > 0;
};

/**
 * Erstellt eine Liste von Bild-URLs
 * @param imagePaths - Array von Bildpfaden
 * @returns Array von vollständigen Bild-URLs
 */
export const getImageUrls = (imagePaths: string[]): string[] => {
  if (!Array.isArray(imagePaths)) return [];
  return imagePaths
    .filter(isValidImagePath)
    .map(getImageUrl);
};

